window.FULLCOOK_CONV=window.FULLCOOK_CONV||[];window.FULLCOOK_CONV.push.apply(window.FULLCOOK_CONV,[{"slug":"denningvleis","t":"Denningvleis","tier":"exotic","cui":"South African \u00b7 Cape Malay","occ":["date","host"],"time":"1 hr 30 min","method":"Stovetop \u00b7 simmer","diff":"Medium","blurb":"Cape Malay's sweet-sour masterpiece \u2014 lamb slow-cooked with cinnamon, tamarind and vinegar in a complex melody of flavours.","prov":{"popular_in":"Cape Malay homes and heritage restaurants","famous_for":"The intricate sweet-sour balance from cinnamon, vinegar, tamarind and sugar that defines this ancient dish","consists_of":"Lamb or mutton slow-cooked with cinnamon sticks, vinegar, tamarind, sugar and aromatics until meltingly tender","name_origin":"From Javanese 'dendeng' (water buffalo meat), one of the oldest recorded recipes in South African cuisine","why_loved":"A symphony of flavours \u2014 sweet, sour, spicy and savoury all in one rich, tender dish","method_detail":"Stovetop \u2014 meat marinated, browned, simmered with cinnamon, vinegar, tamarind and sugar 1\u20131.5 hours until sauce thickens and meat is tender"},"brief":{"lead":"Denningvleis is one of South Africa's oldest recipes, brought by Cape Malay slaves from Java. This sweet-sour lamb stew gets its distinctive flavour from cinnamon sticks, vinegar, tamarind and brown sugar \u2014 a complex melody that slow-cooks into meltingly tender meat with a rich, glossy sauce.","expect":[["Slow-cooked meat","Lamb becomes fork-tender after 90 minutes of gentle simmering"],["Sweet-sour balance","Cinnamon, tamarind and vinegar create the signature Cape Malay flavour profile"],["Rich glossy sauce","The sauce reduces to a thick, caramelised coating for the meat"],["Aromatic depth","Ginger, garlic and allspice add layers to the complex spice blend"]],"stats":[["90","min","Active"],["2","","Serves 2-4"],["Med","","Doneness"],["4","","Spice level"]],"kit":["Heavy-bottomed pot or Dutch oven","Knife and cutting board","Measuring spoons","Wooden spoon"]},"ing":[["Meat & marinade",[["linear",800,"g","<b>lamb</b> shoulder or mutton, cut into 4 cm cubes"],["taper",1,"tbsp","<b>salt</b>"],["taper",1,"tsp","<b>black pepper</b>"],["linear",60,"ml","vinegar"],["taper",1,"tsp","<b>ground coriander</b>"]]],["Aromatics",[["countN",2,"","<b>onions</b>, finely chopped"],["countN",4,"cloves","<b>garlic</b>, crushed"],["linear",2,"cm","fresh ginger, grated"],["linear",2,"sticks","<b>cinnamon</b>"],["taper",1,"tsp","<b>allspice</b> berries"]]],["Sweet-sour sauce",[["linear",60,"ml","<b>tamarind</b> paste or concentrate"],["linear",60,"g","<b>brown sugar</b>"],["linear",125,"ml","hot water"],["linear",30,"ml","vegetable oil"]]],["To serve",[["static","","yellow rice, for serving"],["static","","sambals, for serving"]]]],"tl":[["T-00:00","Marinate lamb","Season meat with vinegar, salt, pepper and coriander",0],["T-00:30","Brown aromatics","Saut\u00e9 onions, garlic, ginger, cinnamon and allspice",0],["T-00:45","Add lamb","Brown meat in spiced onion mixture",0],["T-01:00","Simmer","Slow-cook with tamarind, sugar and water until tender",1],["T-01:30","Rest","Let flavours meld for 10 minutes before serving",1]],"steps":[["Marinate the lamb","Cut lamb into 4 cm cubes. Mix vinegar, salt, pepper and ground coriander. Coat meat and set aside for 30 minutes at room temperature.","The vinegar tenderises meat while coriander adds aromatic depth.",null],["Saut\u00e9 aromatics","Heat oil in heavy pot over medium heat. Add onions, garlic, ginger, cinnamon sticks and allspice berries. Cook 8-10 minutes until onions are softened and fragrant.","Building the aromatic base creates the signature Cape Malay spice foundation.",null],["Brown the lamb","Increase heat to medium-high. Add marinated lamb pieces to the pot. Brown on all sides for 5-6 minutes, stirring occasionally.","Searing develops flavour and colour before the slow simmer.",null],["Add sweet-sour elements","Stir in tamarind paste, brown sugar and hot water. Bring to a simmer, then reduce heat to low. Cover with lid.","The tamarind and sugar create the distinctive sweet-sour balance.",null],["Slow-cook until tender","Simmer gently for 60-75 minutes, stirring occasionally. The lamb should be fork-tender and sauce thickened and glossy.","Slow cooking breaks down connective tissue into melting tenderness.",4200],["Rest the stew","Remove from heat. Let rest, covered, for 10 minutes before serving.","Resting allows flavours to meld and sauce to coat evenly.",600],["Serve and enjoy","Serve over yellow rice with sambals on the side. The lamb should be tender and coated in the rich, sweet-sour sauce.","Complete the Cape Malay experience with traditional accompaniments.",null]]},{"slug":"doro-wat","t":"Doro Wat (Ethiopian Chicken)","tier":"exotic","cui":"Ethiopian","occ":["date","host"],"time":"2 hr","method":"Stovetop \u00b7 simmer","diff":"Medium","blurb":"Ethiopia's celebratory stew \u2014 fiery berbere-spiced chicken with hard-boiled eggs, served with injera.","prov":{"popular_in":"Ethiopian households and festivals, traditionally for special occasions","famous_for":"Ethiopia's national dish \u2014 spicy chicken stew with berbere and hard-boiled eggs","consists_of":"Chicken slow-cooked with onions, berbere spice, niter kibbeh, finished with hard-boiled eggs","name_origin":"Doro = 'chicken', wat = 'stew' \u2014 Ethiopia's most famous dish, served at celebrations","why_loved":"The complex berbere spice blend with rich, slow-cooked onions and tender chicken is unforgettable","method_detail":"Stovetop \u2014 onions caramelised 30+ min, berbere and niter kibbeh added, chicken simmered 45-60 min, hard-boiled eggs added"},"brief":{"lead":"Doro Wat is Ethiopia's national dish \u2014 the centrepiece of celebrations and special occasions. This fiery red stew gets its colour and heat from berbere spice blend, while chicken slow-cooks in a rich sauce of caramelised onions and spiced butter. Hard-boiled eggs simmer in the sauce, absorbing the complex flavours.","expect":[["Caramelised onions","Red onions cook down for 30+ minutes until sweet and golden"],["Berbere spice blend","Ethiopia's signature chilli-coriander-cardamom spice mix"],["Slow-cooked chicken","Pieces simmer until tender and coated in red sauce"],["Spiced eggs","Hard-boiled eggs absorb the rich, spicy flavours"]],"stats":[["120","min","Active"],["2","","Serves 2-4"],["Med","","Doneness"],["Hot","","Heat level"]],"kit":["Heavy pot or Dutch oven","Knife and cutting board","Measuring spoons","Wooden spoon"]},"ing":[["Chicken",[["countX",8,"pieces","<b>chicken</b> (thighs, drumsticks, wings), bone-in, skin-on"],["taper",1,"tbsp","<b>salt</b>"],["taper",1,"tsp","<b>black pepper</b>"]]],["Aromatics & berbere",[["countN",4,"","<b>red onions</b>, finely chopped"],["countN",6,"cloves","<b>garlic</b>, crushed"],["linear",3,"cm","fresh ginger, grated"],["linear",45,"g","<b>berbere</b> spice blend (3-4 tbsp)"],["linear",30,"ml","niter kibbeh (spiced butter) or ghee"],["linear",30,"ml","olive oil"]]],["Sauce & finish",[["linear",250,"ml","chicken stock or water"],["countN",4,"","<b>eggs</b>, hard-boiled and peeled"],["linear",1,"tbsp","<b>lemon juice</b>"],["static","","injera flatbread, for serving"]]],["For niter kibbeh (if making)",[["linear",125,"g","<b>butter</b>"],["countN",2,"cloves","garlic, crushed"],["linear",1,"tsp","ground cardamom"],["linear",1,"tsp","ground cumin"],["linear",0.5,"tsp","ground turmeric"]]]],"tl":[["T-00:00","Prep ingredients","Chop onions, crush garlic, grate ginger"],["T-00:10","Boil eggs","Bring water to boil, add eggs, cook 10 min until hard-boiled"],["T-00:15","Caramelise onions","Cook onions slowly until deep golden and sweet"],["T-00:45","Add berbere","Bloom spices in onions until fragrant and red"],["T-01:00","Brown chicken","Sear chicken pieces in spiced onion mixture"],["T-01:15","Simmer","Cook chicken in stock until tender and coated",1],["T-02:00","Add eggs","Simmer hard-boiled eggs in sauce"],["T-02:10","Rest","Let flavours meld before serving",1]],"steps":[["Prepare the chicken","Pat chicken pieces dry and season with salt and pepper. If making niter kibbeh, melt butter with garlic, cardamom, cumin and turmeric, simmer 5 minutes, strain and set aside.","Seasoning enhances flavour while niter kibbeh adds authentic spiced butter richness.",null],["Caramelise onions","Heat oil and niter kibbeh in heavy pot over medium-low heat. Add onions. Cook 25-30 minutes, stirring occasionally, until deep golden brown and very soft.","Long, slow caramelisation creates the sweet base that balances the fiery berbere.",1500],["Add ginger and garlic","Stir in crushed garlic and grated ginger. Cook 2-3 minutes until fragrant, stirring constantly.","Aromatics build the Ethiopian flavour foundation before spices hit.",null],["Bloom the berbere","Add berbere spice blend. Stir constantly for 2-3 minutes until spices are fragrant and onions are coated in deep red.","Blooming spices in hot fat releases their essential oils and intensifies flavour.",null],["Brown the chicken","Increase heat to medium. Add chicken pieces to the pot. Brown on all sides for 5-6 minutes, turning carefully.","Searing develops colour and flavour before the slow simmer.",null],["Simmer the stew","Pour in chicken stock or water. Bring to a simmer, then reduce heat to low. Cover and simmer 45-50 minutes, turning chicken occasionally.","Slow cooking renders collagen from bone-in chicken into rich, silky sauce.",2700],["Add eggs and finish","Gently nestle hard-boiled eggs into the sauce. Simmer 5-8 minutes until eggs are heated through and coated in sauce. Stir in lemon juice.","Eggs absorb the spicy flavours while lemon brightens the rich stew.",300],["Rest and serve","Remove from heat. Let rest 5 minutes. Serve with injera flatbread to scoop up the sauce.","Resting allows flavours to meld for the authentic Ethiopian experience.",300]]},{"slug":"malva-pudding","t":"Malva Pudding","tier":"others","cui":"South African","occ":["host"],"time":"50 min","method":"Oven \u00b7 bake + sauce","diff":"Easy","pair":[["Wine","Noble Late Harvest","Constantia · South Africa","Luscious apricot-honey depth mirrors the pudding's sticky caramel — a SA dessert-wine classic."],["Spirit","Amarula, over ice","South Africa","Amarula's marula-cream caramel folds into the warm sponge — glass and pudding in conversation."],["Non","Vanilla rooibos iced tea","South Africa","Vanilla rooibos's warmth cradles the sweet sponge without alcohol."]],"blurb":"South Africa's Sunday favourite \u2014 caramelised apricot sponge with hot cream-butter sauce.","prov":{"popular_in":"South African households and Sunday roasts","famous_for":"The beloved South African sponge pudding with apricot jam and cream sauce","consists_of":"Apricot jam sponge cake baked, hot cream-butter sauce poured over, absorbs and creates sticky caramel","name_origin":"Malva possibly from 'malvaleger' \u2014 marshmallow-like soft texture; Dutch-Afrikaner heritage","why_loved":"The sticky, caramelised sponge soaked in hot buttery cream sauce is pure comfort","method_detail":"Oven \u2014 butter, sugar, eggs, apricot jam creamed, dry ingredients added, baked 35 min, hot cream sauce poured over, absorbed 10 min"},"brief":{"lead":"Malva Pudding is South Africa's beloved Sunday dessert \u2014 a golden sponge cake flavoured with apricot jam, baked until fluffy, then drenched in a hot cream-butter sauce that absorbs into the pudding creating a sticky, caramelised texture. Serve warm with custard or ice cream for the ultimate SA comfort food.","expect":[["Apricot sweetness","Jam gives the sponge its distinctive flavour and golden colour"],["Buttery sponge","Creamed butter and sugar create a light, tender crumb"],["Hot cream sauce","Pouring hot sauce over baked pudding creates instant caramelisation"],["Sticky texture","Sauce absorbs deeply for that signature marshmallow-soft centre"]],"stats":[["50","min","Total"],["2","","Serves 4-6"],["Easy","","Difficulty"],["180\u00b0C","","Bake temp"]],"kit":["20 cm square baking dish","Mixing bowls","Electric whisk or wooden spoon","Saucepan"]},"ing":[["Sponge",[["linear",125,"g","<b>butter</b>, softened"],["linear",175,"g","<b>sugar</b>"],["countN",2,"","<b>eggs</b>"],["linear",15,"ml","<b>apricot jam</b>"],["linear",250,"ml","<b>milk</b>"],["linear",15,"ml","white vinegar"],["linear",200,"g","cake flour"],["linear",5,"g","baking powder"],["linear",5,"g","<b>bicarbonate of soda</b>"],["linear",1,"tsp","<b>vanilla</b> extract"],["taper",1,"tsp","<b>salt</b>"]]],["Hot cream sauce",[["linear",250,"ml","<b>cream</b>"],["linear",125,"g","<b>butter</b>"],["linear",125,"g","<b>sugar</b>"],["linear",5,"ml","<b>vanilla</b> extract"],["linear",2.5,"ml","<b>white vinegar</b>"]]],["To serve",[["static","","custard, for serving"],["static","","vanilla ice cream, for serving"]]]],"tl":[["T-00:00","Preheat oven","Heat oven to 180\u00b0C and grease baking dish",0],["T-00:05","Cream butter & sugar","Beat butter and sugar until light and fluffy",0],["T-00:10","Add eggs & jam","Whisk in eggs one at a time, then apricot jam and vanilla",0],["T-00:15","Combine wet & dry","Mix milk and vinegar, fold into flour mixture",0],["T-00:20","Bake","Bake 35 minutes until golden and cooked through",1],["T-00:55","Make sauce","Heat cream, butter, sugar, vanilla and vinegar",0],["T-01:05","Pour & soak","Drench hot pudding in sauce, let absorb",1],["T-01:15","Serve","Serve warm with custard or ice cream",0]],"steps":[["Preheat and prep","Preheat oven to 180\u00b0C. Grease a 20 cm square baking dish with butter.","Preparation ensures the pudding releases easily and bakes evenly.",null],["Cream butter and sugar","Beat softened butter and sugar together until light and fluffy \u2014 about 3-4 minutes with electric whisk or 5-6 by hand.","Creaming incorporates air for a light, tender sponge texture.",null],["Add eggs and flavouring","Add eggs one at a time, beating well after each. Whisk in apricot jam and vanilla extract.","Eggs provide structure while jam gives the distinctive SA flavour.",null],["Combine dry ingredients","Sift flour, baking powder and salt into a separate bowl.","Sifting aerates flour and distributes leavening evenly.",null],["Mix milk and vinegar","Combine milk and white vinegar in a jug, then whisk in the bicarbonate of soda - it will fizz vigorously. Let stand 1 minute until slightly thickened.","Bicarbonate of soda reacts with the vinegar for lift - the signature malva technique.",null],["Complete the batter","Add dry ingredients to butter mixture in three parts, alternating with milk mixture. Fold gently until just combined \u2014 do not overmix.","Gentle folding keeps the sponge tender and prevents toughness.",null],["Bake the pudding","Pour batter into prepared dish. Bake 35-40 minutes until golden brown and a skewer inserted comes out clean.","Baking sets the structure and creates the golden crust.",2100],["Make the hot sauce","While pudding bakes, combine cream, butter, sugar, vanilla and vinegar in a saucepan. Heat gently, stirring, until butter melts and sugar dissolves. Do not boil.","The hot sauce creates instant caramelisation when poured over the pudding.",null],["Pour and soak","Remove pudding from oven. Immediately pour hot sauce evenly over the hot pudding. Let stand 10 minutes to absorb.","Hot sauce absorbs deeply into the sponge, creating the signature sticky texture.",600],["Serve warm","Serve Malva Pudding warm, with custard or vanilla ice cream. The pudding should be sticky, caramelised and soft.","Warm serving is essential for the authentic South African experience.",null]]},{"slug":"peppermint-crisp-tart","t":"Peppermint Crisp Tart","tier":"signature","cui":"South African","occ":["host","date"],"time":"20 min + 6 hours chilling","method":"No-bake \u00b7 assemble","diff":"Easy","pair":[["Spirit","Amarula, over ice","South Africa","Amarula caramel-marula cream echoes the condensed milk and chocolate — a SA dessert-and-spirit duet."],["Wine","Cape Hanepoot (Jerepigo)","South Africa","Sun-ripened Hanepoot grape sweetness stands up to the tart layers of caramel and peppermint chocolate."],["Non","Appletiser","Western Cape · South Africa","Sparkling apple clean fruit refreshes between bites of the rich sticky tart."]],"blurb":"The ultimate South African fridge tart \u2014 layers of coconut biscuits, caramel condensed milk, whipped cream and crushed Peppermint Crisp.","prov":{"popular_in":"Every South African celebration and household fridge","famous_for":"The nostalgic combination of Peppermint Crisp chocolate and caramel that defines South African childhoods","consists_of":"Coconut biscuits layered with whipped cream mixed with caramel condensed milk, topped with crushed Peppermint Crisp bars","name_origin":"Named after the Nestl\u00e9 Peppermint Crisp chocolate bar that defines it; a mid-20th-century South African invention","why_loved":"Cool, creamy, minty and crunchy \u2014 no baking required and always a crowd-pleaser","method_detail":"No-bake \u2014 biscuits layered in a dish, whipped cream mixed with caramel condensed milk, spread over biscuits, topped with crushed Peppermint Crisp, chilled 6 hours, served cold"},"brief":{"lead":"A beloved South African no-bake dessert that layers coconut biscuits with a creamy caramel filling and finishes with crunchy peppermint chocolate. Perfect for celebrations and easy enough for any home cook.","expect":[["Quick prep","Assembly takes 20 minutes \u2014 no baking required"],["Make ahead","Needs 6 hours to chill \u2014 perfect for planning ahead"],["Crowd-pleaser","Serves 8-12 \u2014 ideal for parties and gatherings"],["Nostalgic","The taste of South African childhood celebrations"]],"stats":[["20","min","Active"],["8-12","","Serves"],["6","hrs","Chill"],["Easy","","Difficulty"]],"kit":["Square dish (20\u00d720cm)","Mixing bowls","Whisk or electric beaters","Spatula"]},"ing":[["Base",[["linear",400,"g","<b>Tennis biscuits</b> (coconut biscuits)"],["static","","100 g butter, melted"]]],["Filling",[["linear",400,"g","<b>caramel condensed milk</b>"],["linear",400,"ml","<b>whipping cream</b>"],["taper",1,"tsp","<b>vanilla essence</b>"]]],["Topping",[["linear",3,"","<b>Peppermint Crisp chocolate bars</b>"],["static","","extra Peppermint Crisp for decoration"]]]],"tl":[["T-00:00","Prepare base","Line dish with biscuits",0],["T-00:05","Make filling","Whip cream and caramel",0],["T-00:10","Assemble","Layer filling over base",0],["T-00:15","Add topping","Sprinkle with chocolate",0],["T-06:00","Chill complete","Ready to serve",1]],"steps":[["Prepare the base","Arrange Tennis biscuits in a single layer in the bottom of a 20\u00d720cm dish, breaking some to fit if needed. Drizzle melted butter over biscuits.","Butter helps the base set and adds richness.",null],["Make the filling","Whip the cream until stiff peaks form. Fold in caramel condensed milk and vanilla essence until smooth and combined.","The folding keeps the mixture light and fluffy.",null],["Assemble the tart","Spread the cream-caramel mixture evenly over the biscuit base. Smooth the top with a spatula.","Even layers ensure consistent texture throughout.",null],["Add the topping","Crush 2 Peppermint Crisp bars and sprinkle evenly over the filling. Crush the third bar more finely for decoration.","The crushed chocolate adds the signature minty crunch.",null],["Chill thoroughly","Refrigerate for at least 6 hours, preferably overnight, until set.","Chilling allows the flavours to meld and the tart to set properly.",21600],["Serve","Cut into squares and serve cold. Store leftovers in the fridge.","Best served chilled for the ultimate creamy texture.",null]]},{"slug":"hertzoggies","t":"Hertzoggies","tier":"exotic","cui":"South African \u00b7 Afrikaans","occ":["host","date"],"time":"1 hr","method":"Oven \u00b7 bake","diff":"Medium",  pair: [["Spirit","Amarula, over ice","South Africa","Amarula's caramel-marula cream folds into the chocolate and peppermint like a dream — glass and dessert in blissful conversation."],["Non-alcoholic","Mint rooibos iced tea","South Africa","A cool mint-infused rooibos refreshes the palate, its herbal lift balancing the tart's sugary indulgence."]],
  "blurb":"Afrikaans tartlets \u2014 buttery pastry filled with apricot jam and topped with fluffy coconut meringue.","prov":{popular_in:'A treasured bake of the Cape Malay community, sold at koesister mornings and laid out for afternoon tea across South Africa, passed down through tins that never quite empty for long.',famous_for:'Buttery pastry cups cradling a glossy, coconut-topped crown above a soft, jammy centre of apricot or strawberry that stains the tongue fruit-bright and sweet.',consists_of:'Shortcrust pastry tartlets filled with fruit jam, topped with a baked meringue-and-coconut mixture that toasts golden on top and turns chewy as it cools on the plate.',name_origin:'Named for J.B.M. Hertzog, a South African prime minister — kitchen lore holds that the cookie’s two-tone top of jam and coconut reflected his political promises, woven affectionately into the baking tradition.',why_loved:'Jam-sweet and coconut-chewy in one small, two-toned bite, it carries the warmth of a grandmother’s tin and a kettle that is always on.',method_detail:'Oven — line tart tins, fill, top, then bake golden'},"brief":{"lead":"A classic Afrikaans tea-time treat featuring buttery shortcrust pastry shells filled with sweet apricot jam and topped with fluffy coconut meringue. Named after a former South African Prime Minister, these tartlets are a beloved celebration of Afrikaans heritage.","expect":[[" pastry work","Making and chilling shortcrust pastry"],["Two-stage baking","Blind bake first, then add filling"],["Traditional flavours","Apricot jam and coconut meringue"],["Tea-time classic","Best served with rooibos or Ceylon tea"]],"stats":[["45","min","Active"],["12","","Tartlets"],["180","\u00b0C","Oven"],["Medium","","Difficulty"]],"kit":["Muffin tin","Pastry blender or food processor","Rolling pin","Electric mixer"]},"ing":[["Pastry",[["linear",250,"g","<b>cake flour</b>"],["linear",125,"g","<b>butter</b>, cold and cubed"],["static","","pinch salt"],["linear",45,"ml","<b>ice water</b>"]]],["Filling",[["linear",200,"g","<b>apricot jam</b>"]]],["Meringue",[["countN",2,"","<b>egg whites</b>"],["linear",200,"g","<b>caster sugar</b>"],["taper",1,"tsp","<b>vanilla essence</b>"],["linear",100,"g","<b>desiccated coconut</b>"]]]],"tl":[["T-00:00","Make pastry","Mix and chill dough",0],["T-00:15","Line tins","Fill muffin tins with pastry",0],["T-00:25","Blind bake","Bake pastry shells empty",0],["T-00:35","Fill shells","Add apricot jam",0],["T-00:40","Make meringue","Whip egg whites and sugar",0],["T-00:45","Top and bake","Add meringue and finish baking",0],["T-01:00","Cool","Ready to serve",0]],"steps":[["Make the pastry","Rub cold butter into flour and salt until mixture resembles breadcrumbs. Add ice water and mix until dough just comes together. Shape into a disc, wrap and chill for 15 minutes.","Cold butter and chilling prevent shrinkage during baking.",900],["Prepare the tart shells","Roll out pastry to 3mm thickness. Cut circles to fit a 12-hole muffin tin. Press pastry into tins, trimming edges. Prick bases with a fork and chill 10 minutes.","Chilling again helps pastry hold its shape.",600],["Blind bake","Line pastry shells with baking paper and fill with baking beans. Bake at 180\u00b0C for 10\u201312 minutes until lightly golden. Remove paper and beans.","Blind baking ensures the pastry is fully cooked.",null],["Fill with jam","Spoon a generous teaspoon of apricot jam into each hot pastry shell. Spread slightly to cover the bottom.","The hot pastry helps the jam settle evenly.",null],["Make the meringue","Whisk egg whites until soft peaks form. Gradually add sugar, whisking until glossy and stiff. Fold in vanilla essence and coconut.","Stiff peaks ensure the meringue holds its shape.",null],["Top the tartlets","Spoon meringue over each jam-filled shell, spreading to seal edges. Sprinkle with extra coconut if desired.","Sealing edges prevents jam from bubbling over.",null],["Bake until golden","Return to oven at 180\u00b0C for 12\u201315 minutes until meringue is lightly golden and set.","Watch carefully \u2014 coconut can brown quickly.",900],["Cool and serve","Cool in tin for 5 minutes, then carefully transfer to wire rack. Serve warm or at room temperature with tea.","Cooling in the tin helps set the meringue.",300]]},{"slug":"lamb-tagine-apricot-almond","t":"Lamb Tagine, Apricot & Almond","tier":"exotic","cui":"Moroccan","occ":["date","host"],"time":"2 hr","method":"Stovetop \u00b7 slow-cook","diff":"Medium","blurb":"Morocco's fragrant stew \u2014 tender lamb with dried apricots, almonds, and aromatic spices.","prov":{"popular_in":"Moroccan households and North African restaurants","famous_for":"The classic Moroccan tagine with lamb, dried fruit, and nuts in spiced sauce","consists_of":"Lamb shoulder slowly cooked with onions, spices (cumin, coriander, cinnamon), dried apricots, almonds","name_origin":"Tagine = both the conical cooking vessel and the stew; Moroccan Berber tradition","why_loved":"The sweet-savoury combination of tender lamb, sweet apricots, and crunchy almonds with warm spices","method_detail":"Stovetop \u2014 lamb browned, onions slowly caramelised, spices, apricots, almonds added, stock, simmered 90-120 min until tender, garnished with almonds"},"brief":{"lead":"A classic Moroccan slow-cooked stew featuring tender lamb shoulder, sweet dried apricots, and crunchy almonds in a richly spiced sauce. The perfect balance of sweet and savoury, this tagine brings the flavours of North Africa to your table.","expect":[["Slow cooking","2 hours of gentle simmering for meltingly tender lamb"],["Aromatic spices","Cumin, coriander, cinnamon and saffron create depth"],["Sweet-savoury","Apricots balance the rich lamb"],["One-pot wonder","Everything cooks together for layered flavours"]],"stats":[["30","min","Prep"],["90-120","min","Simmer"],["2-4","","Serves"],["Medium","","Difficulty"]],"kit":["Heavy-based pot or tagine","Sharp knife","Cutting board","Wooden spoon"]},"ing":[["Meat and aromatics",[["linear",800,"g","<b>lamb shoulder</b>, cut into 4cm cubes"],["countN",2,"","<b>onions</b>, finely chopped"],["countN",4,"","<b>garlic cloves</b>, crushed"],["static","","30 ml olive oil"]]],["Spices",[["taper",2,"tsp","<b>ground cumin</b>"],["taper",1,"tsp","<b>ground coriander</b>"],["taper",1,"","<b>cinnamon stick</b>"],["taper",0.5,"tsp","<b>ground ginger</b>"],["static","","pinch saffron threads"],["static","","salt and black pepper"]]],["Fruit and nuts",[["linear",200,"g","<b>dried apricots</b>"],["linear",100,"g","<b>blanched almonds</b>"],["static","","50 g toasted almonds for garnish"]]],["Liquids",[["linear",500,"ml","<b>lamb or chicken stock</b>"],["static","","2 tbsp honey"],["static","","preserved lemon (optional)"]]]],"tl":[["T-00:00","Prep ingredients","Cut meat and chop aromatics",0],["T-00:10","Brown lamb","Sear meat in batches",0],["T-00:20","Caramelize onions","Cook onions slowly until golden",0],["T-00:35","Add spices","Toast spices with aromatics",0],["T-00:40","Combine and simmer","Add meat, fruit, stock",0],["T-02:00","Finish","Garnish and serve",0]],"steps":[["Prep the lamb","Cut lamb shoulder into 4cm cubes, trimming excess fat. Pat dry with paper towel.","Dry meat browns better for deeper flavour.",null],["Brown the lamb","Heat olive oil in a heavy-based pot over medium-high heat. Season lamb with salt and pepper. Brown in batches \u2014 don't overcrowd the pan. Set aside.","Batch browning prevents steaming and develops colour.",null],["Caramelize onions","Reduce heat to medium. Add onions to the pot with a pinch of salt. Cook slowly for 10\u201312 minutes until golden and soft, scraping up the browned bits from the bottom.","Caramelized onions provide the flavour base.",null],["Add aromatics and spices","Add garlic, cumin, coriander, ginger, cinnamon stick and saffron. Cook for 1 minute until fragrant, stirring constantly.","Blooming spices releases their essential oils.",60],["Combine everything","Return lamb to the pot. Add apricots, blanched almonds, stock and honey. Stir to combine. Bring to a simmer, then reduce heat to low.","Honey balances the tartness of apricots.",null],["Slow cook","Cover and simmer gently for 90\u2013120 minutes until lamb is meltingly tender. Check occasionally and add a splash of water if needed.","Slow cooking breaks down connective tissue.",7200],["Finish and serve","Remove cinnamon stick. Stir in preserved lemon if using. Taste and adjust seasoning. Sprinkle with toasted almonds. Serve with couscous or flatbread.","Toasted almonds add essential crunch.",null]]},{"slug":"chicken-biryani","t":"Chicken Biryani","tier":"global","cui":"Indian \u00b7 Mughlai","occ":["host","date"],"time":"2 hr","method":"Stovetop \u00b7 layered cook","diff":"Hard",  pair: [["Wine","Wooded Chenin Blanc","South Africa","Aromatic wooded Chenin mirrors the biryani's layered spice, its gentle richness cradling the saffron rice."],["Beer","Windhoek Lager","South Africa","A pure, clean Windhoek rinses the palate bright between each fragrant, spiced forkful."],["Non-alcoholic","Spiced rooibos iced tea","South Africa","A spiced rooibos chiller picks up the biryani's cardamom and clove without ever turning up the heat."]],
  "blurb":"Indian celebration rice - layered chicken and rice with saffron, spices, and fried onions.","prov":{popular_in:'The crown of festive tables across the Indian subcontinent and the South African Indian communities of Durban and KwaZulu-Natal, served at weddings, Eid, and any gathering worth its salt.',famous_for:'Layers of saffron-streaked rice and spiced chicken lifted apart with a fork to release a fragrant cloud of steam and a mosaic of fried onion, mint, and whole spice.',consists_of:'Yogurt-marinated chicken layered with parboiled basmati rice, whole spices, fried onions, saffron, and fresh herbs, then sealed and dum-cooked until each grain stands separate and fluffy.',name_origin:'From the Persian birian, meaning ‘fried before cooking’ — biryani travelled to India with Persian influences and was refined to grandeur in the Mughal imperial kitchens.',why_loved:'Every spoonful holds a slightly different balance of spice, colour, and texture — a dish engineered for abundance, generosity, and the joy of the crowd.',method_detail:'Stovetop — layer, seal the pot, then steam on low heat'},"brief":{"lead":"A grand Indian celebration dish where fragrant basmati rice and spiced chicken are cooked separately, then layered with caramelised onions, saffron milk, and fresh herbs, and steamed together (dum) until the aromas meld into perfection.","expect":[["Marinate","Chicken in yoghurt and spices for maximum flavour penetration"],["Par-cook","Basmati rice to 70% - it finishes steaming with the chicken"],["Layer","Rice, chicken, fried onions, saffron milk in heavy pot"],["Dum steam","Tightly sealed on low heat until flavours meld"]],"stats":[["120","min","Active"],["2","","Serves 2-4"],["Med-High","","Effort"],["6","","Layers"]],"kit":["Heavy pot with tight lid","Large saucepan","Frying pan","Bowls for prep"]},"ing":[["Chicken & marinade",[["linear",800,"g","<b>chicken pieces</b>, bone-in, mixed cuts"],["linear",250,"g","yoghurt, full-fat"],["taper",2,"tbsp","ginger-garlic paste"],["taper",2,"tsp","<b>chilli powder</b>"],["taper",1,"tsp","<b>turmeric</b>"],["taper",1,"tsp","<b>garam masala</b>"],["taper",1,"tsp","salt"],["static","","lemon juice"]]],["Whole spices",[["countN",3,"","<b>green cardamom pods</b>"],["countN",2,"","<b>cloves</b>"],["countN",1,"","<b>cinnamon stick</b>, 5cm"],["countN",4,"","<b>black peppercorns"],["countN",2,"","<b>bay leaves"],["static","","star anise, optional"]]],["Rice & layering",[["linear",400,"g","<b>basmati rice</b>"],["linear",150,"g","<b>onions</b>, thinly sliced"],["linear",80,"ml","<b>ghee</b> or oil"],["linear",60,"ml","milk, warm"],["taper",0.5,"tsp","<b>saffron strands</b>"],["countN",4,"","<b>mint sprigs</b>, fresh"],["countN",4,"","<b>coriander sprigs</b>, fresh"],["static","","rose water, few drops"]]]],"tl":[["T-00:00","Prep & marinate","Chicken in spices, onions frying, rice soaking",0],["T-00:30","Cook chicken","Simmer spiced chicken until tender",0],["T-01:00","Par-cook rice","Boil rice to 70% with whole spices",0],["T-01:20","Layer & dum","Assemble layers, seal pot, steam on lowest heat",0],["T-02:00","Rest & serve","Let flavours meld, gently mix layers",1]],"steps":[["Marinate the chicken","Mix chicken with yoghurt, ginger-garlic paste, chilli powder, turmeric, garam masala, salt, and lemon juice. Let marinate at room temperature for 30-60 minutes.","Yoghurt tenderises and spices penetrate deep.",null],["Fry the onions","Heat ghee in a frying pan. Fry sliced onions slowly over medium heat until deeply golden and caramelised, about 20 minutes. Remove and drain on paper towels.","Caramelised onions (birista) are the flavour backbone.",1200],["Cook the chicken","In a heavy pot, heat 2 tablespoons ghee. Add whole spices (cardamom, cloves, cinnamon, peppercorns, bay leaves) for 30 seconds until fragrant. Add marinated chicken and cook over medium-high heat for 5-7 minutes until sealed on all sides. Reduce heat, cover, and simmer for 20-25 minutes until chicken is 80% cooked.","Building the base flavour and par-cooking the meat.",1500],["Par-cook the rice","While chicken simmers, soak basmati rice in cold water for 20 minutes. Drain. Boil 2 litres water with salt. Add rice and boil for 4-5 minutes until grains are 70% cooked (still slightly firm in centre). Drain thoroughly.","Rice finishes cooking in the dum with chicken juices.",600],["Prepare saffron milk","Warm the milk and crush saffron strands into it. Let steep for 10 minutes until golden. Add rose water if using.","Saffron perfume and colour the top rice layer.",600],["Layer the biryani","In the heavy chicken pot, spread half the chicken at the bottom. Top with half the rice. Sprinkle with some fried onions, mint, and coriander. Repeat layers: remaining chicken, remaining rice, remaining fried onions, herbs. Pour saffron milk evenly over the top.","Layering builds flavour gradients as steam rises through.",null],["Dum steam","Cover pot tightly with foil, then the lid (seal edges with dough if extremely particular). Place on lowest heat for 20-25 minutes. Alternatively, place in preheated 160C oven for 20 minutes.","Dum steaming melds flavours and completes cooking.",1500],["Rest and serve","Remove from heat and let rest, covered, for 10 minutes. Gently mix layers with a flat spatula, serving from the bottom to preserve the saffron top. Serve with raita.","Resting redistributes moisture; gentle mixing keeps layers intact.",600]]},{"slug":"red-wine-braised-short-rib","t":"Red-Wine Braised Short Rib","tier":"premium","cui":"Modern \u00b7 American","occ":["host","date"],"time":"4 hr","method":"Oven \u00b7 slow braise","diff":"Medium","blurb":"Modern classic - beef short ribs slowly braised in red wine until falling apart.","prov":{"popular_in":"Modern American restaurants; dinner party menus","famous_for":"The ultimate make-ahead showpiece - fork-tender with rich wine sauce","consists_of":"Beef short ribs slowly braised in red wine with aromatics until fork-tender","name_origin":"Modern American adaptation of French boeuf bourguignon technique","why_loved":"Fork-tender rich beef, deep wine sauce, impressive presentation, make-ahead friendly","method_detail":"Oven - short ribs browned, braised in red wine at 160C for 3-4 hours until tender"},"brief":{"lead":"A luxurious make-ahead main where beef short ribs are deeply browned, then slowly braised in red wine with aromatics until the meat yields to a fork and the wine reduces to a glossy, intensely flavoured sauce.","expect":[["Sear hard","Short ribs until deeply caramelised - this builds the flavour base"],["Braise slow","In oven at 160C for 3+ hours until meltingly tender"],["Reduce sauce","Until rich and glossy, coating the back of a spoon"],["Make-ahead","Flavours improve overnight; reheat gently"]],"stats":[["60","min","Active"],["180","min","Passive"],["2","","Serves 4-6"],["Low","","Effort"]],"kit":["Dutch oven or heavy braising pot","Large frying pan","Tongs","Fine mesh sieve"]},"ing":[["Beef & sear",[["linear",1200,"g","<b>beef short ribs</b>, bone-in, cut into 5cm pieces"],["taper",2,"tsp","salt"],["taper",1,"tsp","<b>black pepper</b>"],["linear",30,"ml","oil, neutral"]]],["Aromatics",[["linear",200,"g","<b>onions</b>, diced"],["linear",100,"g","<b>carrots</b>, diced"],["linear",100,"g","<b>celery</b>, diced"],["countN",4,"","<b>garlic cloves</b>, crushed"],["linear",60,"ml","<b>tomato paste</b>"],["linear",750,"ml","<b>red wine</b>, full-bodied (Cabernet/Shiraz)"],["linear",500,"ml","<b>beef stock</b>"],["countN",2,"","<b>bay leaves"],["countN",4,"","<b>thyme sprigs</b>"],["countN",2,"","<b>rosemary sprigs</b>"]]],["Finish",[["static","","cornflour slurry (optional)"],["static","","salt and black pepper to taste"]]]],"tl":[["T-00:00","Sear beef","Brown short ribs deeply on all sides",0],["T-00:20","Build base","Saut\u00e9 vegetables, add tomato paste, deglaze with wine",0],["T-00:40","Braise","Cover and transfer to 160C oven for 3+ hours",0],["T-04:00","Finish sauce","Strain, reduce, adjust seasoning",0],["T-04:20","Rest & serve","Fat floats to top, skim and serve",1]],"steps":[["Season and prep","Pat short ribs dry with paper towels. Season generously with salt and pepper. Let sit at room temperature for 20 minutes while you dice vegetables.","Taking the chill off ensures even searing.",1200],["Sear the beef","Heat oil in a large heavy pan over high heat until smoking. Sear short ribs in batches, 2 minutes per side, until deeply browned on all sides. Don't crowd the pan. Transfer to a plate.","Deep caramelisation = depth of flavour in the final sauce.",1800],["Build the braising base","Pour off excess fat, leaving 2 tablespoons in the pan. Reduce heat to medium. Add onions, carrots, celery, and garlic. Cook 8-10 minutes until softened and lightly browned. Add tomato paste and cook 2 minutes, stirring constantly, until darkened and rust-coloured.","Tomato paste caramelisation adds sweet-savoury base notes.",600],["Deglaze and assemble","Pour in red wine and bring to a boil, scraping up browned bits from the pan bottom. Simmer 5 minutes until reduced by half. Add beef stock, bay leaves, thyme, and rosemary. Return short ribs to the pot along with any resting juices.","Wine reduction concentrates flavour; herbs infuse the sauce.",300],["Braise","Cover with a tight-fitting lid and transfer to a 160C oven. Braise for 3-3.5 hours until meat yields easily when pierced with a fork and pulls away from the bone.","Low, slow heat breaks down collagen into gelatinous richness.",10800],["Finish the sauce","Remove pot from oven. Transfer short ribs to a bowl and cover loosely. Strain the cooking liquid through a fine mesh sieve into a clean pan, pressing on solids to extract all liquid. Discard vegetables. Bring sauce to a simmer and reduce for 5-10 minutes until glossy and coating the back of a spoon. If too thin, whisk in a little cornflour slurry and simmer 1 minute. Season with salt and pepper.","Reduction concentrates the hours of braise into a velvety sauce.",600],["Rest and serve","Return short ribs to the sauce. Let rest off heat for 15 minutes (or overnight in the fridge - reheat gently). The fat will rise to the surface - skim it off. Serve short ribs in glossy sauce with mashed potatoes or creamy polenta.","Resting redistributes juices; skimming removes excess fat.",900]]},{"slug":"roast-leg-lamb-rosemary-garlic","t":"Roast Leg of Lamb, Rosemary & Garlic","tier":"premium","cui":"Mediterranean \u00b7 Greek","occ":["host"],"time":"2 hr","method":"Oven \u00b7 roast","diff":"Medium","blurb":"Easter Sunday classic - leg of lamb roasted with rosemary, garlic, and lemon.","prov":{"popular_in":"Greek Easter; Mediterranean Sunday roasts","famous_for":"The festive centrepiece - crusty herb exterior, pink juicy interior","consists_of":"Whole leg of lamb studded with garlic and rosemary, roasted with lemon","name_origin":"Greek Pascha tradition; Mediterranean Easter staple","why_loved":"Crispy herb crust, pink aromatic meat, natural jus for dipping","method_detail":"Oven - lamb studded with garlic-rosemary, roasted at 200C until medium-rare"},"brief":{"lead":"An impressive Easter classic where a whole leg of lamb is studded with garlic and rosemary, rubbed with olive oil and lemon, then roasted at high heat for a crisp, herb-flecked crust and blushing pink interior.","expect":[["Stud","Lamb with garlic and rosemary slivers all over"],["Season","Generously with olive oil, lemon, salt, pepper"],["Roast hot","At 200C for 20 minutes, then reduce to 180C"],["Rest well","Crucial for juicy medium-rare meat"]],"stats":[["20","min","Prep"],["90","min","Roast"],["20","min","Rest"],["2-6","","Serves"]],"kit":["Roasting tin with rack","Sharp knife","Small board","Meat thermometer (optional)"]},"ing":[["Lamb & crust",[["linear",2000,"g","<b>leg of lamb</b>, bone-in, about 2kg"],["countN",4,"","<b>garlic cloves</b>, cut into slivers"],["countN",6,"","<b>rosemary sprigs</b>, fresh"],["linear",60,"ml","<b>olive oil</b>"],["countN",2,"","<b>lemons</b>"],["taper",2,"tbsp","salt"],["taper",1,"tbsp","<b>black pepper</b>"]]],["Jus (optional)",[["linear",200,"ml","<b>white wine</b> or chicken stock"],["countN",2,"","garlic cloves, crushed"],["static","","fresh rosemary sprigs"]]]],"tl":[["T-00:00","Prep lamb","Score fat, stud with garlic-rosemary, rub with oil-lemon",0],["T-00:20","Roast hot","At 200C for 20 minutes to sear exterior",0],["T-00:40","Roast medium","Reduce to 180C for 50-70 minutes until medium-rare",0],["T-01:30","Rest","Tented loosely for 20 minutes before carving",1],["T-01:50","Carve & serve","Slice against the grain, serve with jus",0]],"steps":[["Prep the lamb","Remove lamb from fridge 1 hour before cooking. Pat dry with paper towels. Using a sharp knife, make small slits all over the lamb about 2cm deep. Insert a garlic sliver and a small sprig of rosemary into each slit. Drizzle with juice of 1 lemon and rub all over with olive oil. Season generously with salt and pepper, massaging into the meat.","Taking the chill off ensures even cooking; slitting distributes flavour through the meat.",3600],["Preheat oven","Place roasting tin on the middle rack and preheat to 200C. This gets the tin hot for a good sear.","Hot tin = crusty bottom from the start.",null],["Initial sear","Place lamb on the rack in the hot roasting tin (fat-side up). Roast at 200C for 20 minutes until the fat is rendered and golden.","High heat creates the crust; medium heat finishes the interior.",1200],["Roast to medium-rare","Reduce oven to 180C. Roast for 50-70 minutes (15-18 minutes per 500g) until internal temperature reaches 54-56C for medium-rare, or 60C for medium. Baste halfway through with pan juices. If the fat browns too quickly, cover loosely with foil.","The carryover cooking during resting will finish it to perfection.",3600],["Rest the lamb","Transfer lamb to a carving board. Tent loosely with foil and rest for 20 minutes. The temperature will rise 3-4 degrees and juices will redistribute.","Resting is non-negotiable - it's what makes the meat juicy.",1200],["Make the jus (optional)","While lamb rests, pour off excess fat from the roasting tin. Place tin on the stovetop over medium heat. Add white wine or stock, scraping up browned bits. Add crushed garlic and rosemary. Simmer for 5 minutes until slightly reduced. Strain if desired.","The jus captures all the roasted flavour for serving.",300],["Carve and serve","Carve lamb against the grain into thin slices. Arrange on a warmed platter and drizzle with the jus. Serve with roasted potatoes, minted peas, and a crisp green salad.","Carving against the grain ensures tenderness in every bite.",null]]},{"slug":"creme-brulee","t":"Cr\u00e8me Br\u00fbl\u00e9e","tier":"others","cui":"French","occ":["date","host"],"time":"1 hr (plus chilling)","method":"Oven \u00b7 bake + torch","diff":"Medium","pair":[["Wine","Noble Late Harvest","Constantia · South Africa","The honeyed botrytis sweetness echoes the caramelised sugar crown — richer than the custard, the golden rule of dessert wine."],["Sparkling","MCC","Robertson · South Africa","Fine Cap Classique bubbles cut the richness and lift the burnt sugar, brightening each spoonful."],["Non","Vanilla rooibos iced tea","South Africa","Soft vanilla rooibos warmth complements the custard without competing with the caramel."]],"blurb":"French restaurant classic \u2014 silky vanilla custard with caramelised sugar crust.","prov":{"popular_in":"French restaurants and fine dining globally","famous_for":"The classic French vanilla custard with crackling caramelised sugar top","consists_of":"Rich egg-cream custard flavoured with vanilla, baked, topped with sugar, caramelised until crisp","name_origin":"'Burnt cream' \u2014 originated in Catalonia as crema catalana, adopted into French cuisine","why_loved":"The contrast of silky cool custard with warm crackling caramelised sugar is magical","method_detail":"Oven \u2014 cream infused with vanilla, yolks and sugar whisked, combined, baked in water bath 35-45 min, chilled, sugared, torched"},"brief":{"lead":"Cr\u00e8me br\u00fbl\u00e9e is the ultimate French dinner party dessert \u2014 deceptively simple but requiring technique. A water bath ensures gentle, even cooking for that signature silky texture. The magic happens at the end: a layer of sugar torched until it crackles, creating that satisfying contrast between cool custard and warm caramel.","expect":[["Silky texture","Proper water bath baking prevents curdling and ensures smooth custard"],["Crisp caramel top","Sugar torched until amber and crackling"],["Rich vanilla flavour","Infused properly into the cream"],["Restaurant presentation","Individual ramekins for elegant service"]],"stats":[["45","min","Active"],["4-6","hr","Chilling"],["150","\u00b0C","Oven"],["4","","Serves"]],"kit":["Whisk","Fine-mesh sieve","Kitchen torch","4 ramekins (150-180ml)","Baking dish (for water bath)"]},"ing":[["Custard base",[["linear",500,"ml","<b>heavy cream</b>"],["linear",1,"","<b>vanilla bean</b>, split and seeds scraped (or 2 tsp extract)"],["countN",5,"","<b>egg yolks</b>"],["linear",100,"g","<b>caster sugar</b>"],["taper",0.25,"tsp","<b>salt</b>"]]],["Caramel topping",[["static","","<b>caster sugar</b>, for topping (approx. 4 tbsp)"]]]],"tl":[["T-00:00","Infuse cream","Heat cream with vanilla until just simmering, then steep",0],["T-00:15","Prepare custard","Whisk yolks with sugar, combine with cream",0],["T-00:25","Bake in water bath","Bake at 150\u00b0C for 35-45 min until set but wobbly",2700],["T-01:20","Chill thoroughly","Refrigerate at least 4 hours or overnight",14400],["T-01:20","Caramelise and serve","Sugar top, torch until amber, serve immediately",0]],"steps":[["Infuse the cream","Pour cream into a saucepan. Scrape vanilla seeds into the cream, add the pod. Bring to just below simmer over medium heat, then remove from heat and let steep 15 min. Discard pod.","Infusing extracts maximum vanilla flavour.",900],["Prepare the egg mixture","Whisk egg yolks, sugar, and salt in a heatproof bowl until thick and pale, about 2 min. Do not over-whisk or incorporate air.","Thick yolks create proper custard structure.",null],["Temper and combine","Remove vanilla pod from cream. Reheat cream until just hot. Slowly whisk about 100ml hot cream into the yolks (tempering), then return mixture to saucepan. Cook over lowest heat, stirring constantly, until slightly thickened and coating the back of a spoon (80-82\u00b0C on thermometer).","Tempering prevents scrambling eggs; gentle cooking thickens without curdling.",300],["Strain and fill ramekins","Pour custard through fine-mesh sieve into a jug (removes any cooked bits). Divide evenly among 4 ramekins. Place ramekins in a baking dish. Pour boiling water into the baking dish to reach halfway up the sides of ramekins.","Straining ensures silky texture; water bath provides gentle, even heat.",null],["Bake until set","Bake at 150\u00b0C for 35-45 min until edges are set but centre still wobbles like jelly (it will firm as it chills). Remove ramekins from water bath immediately to stop cooking.","Low, gentle heat prevents curdling; residual heat completes cooking.",2700],["Chill thoroughly","Cool at room temperature 30 min, then refrigerate uncovered 1 hour until cold. Cover and refrigerate at least 4 hours or overnight \u2014 custard must be completely cold for best caramelisation.","Proper chilling develops texture and ensures sugar crackles properly.",1800],["Caramelise the tops","Just before serving, blot any condensation from custard surface. Sprinkle 1 tbsp sugar evenly over each custard, tilting to coat. Shake off excess sugar. Using a kitchen torch, caramelise sugar until deep amber and bubbling, moving flame constantly. Cool 2 min until sugar hardens and crackles.","Even sugar layer ensures proper crackle; torch creates signature caramel crust.",120],["Serve immediately","Serve within 10-15 min while sugar is still crisp. The contrast of warm crackling caramel with cool silky custard is the magic.","Timely service preserves the signature texture contrast.",null]]},{"slug":"tiramisu","t":"Tiramisu","tier":"others","cui":"Italian","occ":["date","host"],"time":"30 min (plus chilling)","method":"No-bake \u00b7 assemble","diff":"Medium","pair":[["Wine","MCC","Robertson · South Africa","Fine Cap Classique bubbles and brioche lift the espresso-soaked mascarpone — elegance meets indulgence."],["Spirit","KWV Brandy","Western Cape · South Africa","A small brandy alongside echoes the coffee and cocoa warmth — the Italian-South African after-dinner finish."],["Non","Iced rooibos latte","South Africa","A creamy iced rooibos mirrors the coffee-and-cream layers, minus the caffeine and heaviness."]],"blurb":"Italy's coffee classic \u2014 espresso-dipped ladyfingers with mascarpone cream, dusted with cocoa.","prov":{"popular_in":"Italian trattorias and dessert menus globally","famous_for":"The iconic Italian no-bake dessert with coffee-soaked ladyfingers and mascarpone","consists_of":"Savoiardi (ladyfingers) dipped in espresso, layered with mascarpone-cream mixture, cocoa-dusted","name_origin":"Tiramisu = 'pick me up' \u2014 from coffee kick and sugar energy; invented in 1960s Veneto","why_loved":"The coffee-soaked biscuits with silky mascarpone cream and bitter chocolate dust is perfection","method_detail":"No-bake \u2014 egg yolks whipped with sugar, mascarpone folded, ladyfingers dipped in espresso-rum, layered, chilled 4+ hours, cocoa-dusted"},"brief":{"lead":"Tiramisu is Italy's most famous dessert \u2014 a perfect balance of strong coffee, rich mascarpone cream, and bitter cocoa. The key is the texture contrast: crisp ladyfingers soften just enough in the coffee mixture, while staying supported by the silky cream. Proper chilling time is non-negotiable \u2014 this dessert needs 4+ hours to meld flavours and achieve that iconic fork-tender texture.","expect":[["Silky mascarpone cream","Properly whipped and folded for light, rich texture"],["Perfectly soaked biscuits","Dipped, not drowned \u2014 ladyfingers should be tender, not mushy"],["Strong coffee flavour","Espresso provides the classic Italian kick"],["Cocoa-dusted finish","Bitter-sweet balance to rich cream"]],"stats":[["25","min","Active"],["4-6","hr","Chilling"],["No","bake","Required"],["6-8","","Serves"]],"kit":["Electric whisk or stand mixer","Shallow dish (for dipping ladyfingers)","23cm square or rectangular dish","Sieve (for cocoa dusting)"]},"ing":[["Mascarpone cream",[["countN",5,"","<b>egg yolks</b> (room temp)"],["linear",100,"g","<b>caster sugar</b>"],["linear",500,"g","<b>mascarpone cheese</b>, room temp"],["taper",0.5,"tsp","<b>vanilla extract</b>"],["countN",150,"ml","<b>double cream</b>, optional (for stability)"]]],["Coffee mixture",[["linear",300,"ml","<b>strong espresso</b>, cooled"],["linear",2,"tbsp","<b>dark rum</b> or brandy (optional)"],["linear",2,"tbsp","<b>caster sugar</b> (dissolved warm)"]]],["Assembly",[["linear",200,"g","<b>savoiardi</b> (ladyfingers)"],["linear",30,"g","<b>cocoa powder</b>, Dutch-processed (for dusting)"]]]],"tl":[["T-00:00","Prepare coffee mixture","Brew espresso, add rum if using, cool completely",0],["T-00:05","Make mascarpone cream","Whisk yolks with sugar until thick, fold in mascarpone",0],["T-00:15","Assemble layers","Dip ladyfingers, layer with cream, repeat, finish with cream",0],["T-00:25","Chill and develop","Refrigerate at least 4 hours or overnight",14400],["T-00:25","Dust and serve","Cocoa dusting immediately before serving",0]],"steps":[["Prepare coffee mixture","Brew strong espresso and cool to room temperature. If using rum or brandy, stir in now. Add 2 tbsp sugar, stirring until dissolved. Pour into a shallow dish wide enough to dip ladyfingers.","Cool coffee prevents melting mascarpone; shallow dish ensures even dipping.",300],["Make the yolk base","Whisk egg yolks and sugar in a heatproof bowl over a pan of simmering water (double boiler) until thick, pale, and doubled in volume \u2014 about 5 min. Remove from heat and whisk until cool (or use electric whisk 3-4 min). This stabilises the cream.","Cooked yolks are safer and create stable structure.",null],["Fold in mascarpone","Add vanilla to yolk mixture. In a separate bowl, whisk mascarpone briefly to loosen (do not overwhisk or it will split). Fold mascarpone into yolk mixture in 3 additions until combined. If using double cream for stability, whip to soft peaks now and fold in.","Gentle folding keeps cream light and prevents splitting.",null],["Dip ladyfingers","Working quickly, dip each ladyfinger into coffee mixture for exactly 1-2 seconds per side \u2014 they should be moistened but not soggy. Do not soak.","Quick dipping creates tender layers without mushiness.",null],["First layer","Arrange dipped ladyfingers in a single layer in your dish (break to fit if needed). Spread with half the mascarpone cream, smoothing top.","Even layers ensure consistent texture throughout.",null],["Second layer","Repeat dipping and layering ladyfingers. Top with remaining mascarpone cream, spreading smoothly. Cover tightly with cling film.","Double layering creates proper depth of flavour.",null],["Chill thoroughly","Refrigerate at least 4 hours, preferably overnight. This is essential \u2014 ladyfingers soften completely and flavours meld into that classic tiramisu texture.","Proper chilling is non-negotiable for authentic texture.",1800],["Finish and serve","Just before serving, sift cocoa powder generously over the top. Cut into squares and serve cold. The cocoa provides the perfect bitter-sweet balance to the rich cream.","Cocoa dusting completes the classic flavour profile.",null]]},{"slug":"croissants","t":"Croissants","tier":"others","cui":"French \u00b7 Bakery","occ":["solo","date"],"time":"2 hr (plus lamination and proving)","method":"Oven \u00b7 laminate","diff":"Hard","blurb":"The French bakery classic - flaky, buttery crescents of laminated dough.","prov":{"popular_in":"France; bakeries worldwide; brunch staple","famous_for":"The ultimate French pastry - 27 layers of buttery flaky dough","consists_of":"Laminated yeast dough with butter, shaped into crescents, baked until golden","name_origin":"Austrian kipferl adapted in France; crescent shape celebrates victory","why_loved":"Buttery flavour, shatteringly crisp layers, tender interior, French breakfast perfection","method_detail":"Oven - dough laminated with butter, proved, baked at 200\u00b0C until golden"},"brief":{"lead":"Croissants are the pinnacle of French patisserie \u2014 a testament to patience, precision, and butter. The magic lies in lamination: folding butter into dough to create paper-thin alternating layers that puff into golden flaky crescents. This is a 2-3 day process: make d\u00e9trempe (dough) day 1, laminate day 2, prove and bake day 3. Temperature control is critical \u2014 butter must stay cold but pliable throughout. The reward? 27 layers of buttery perfection that shatters at first bite.","expect":[["27 buttery layers","Proper lamination creates signature flaky texture"],["Golden exterior","Egg wash creates deep mahogany colour"],["Tender interior","Proper proving creates open, airy crumb"],["Freshly baked aroma","The smell is half the magic"]],"stats":[["2-3","days","Process"],["30","min","Active per day"],["200","\u00b0C","Oven"],["8","","Yields"]],"kit":["Rolling pin","Ruler (for measuring dough)","Bench scraper","Pastry brush","Baking tray","Clean work surface (cool)"]},"ing":[["D\u00e9trempe (dough)",[["linear",350,"g","<b>plain flour</b> (strong bread flour preferred)"],["linear",30,"g","<b>caster sugar</b>"],["taper",2.5,"tsp","<b>instant yeast</b>"],["taper",2,"tsp","<b>salt</b>"],["linear",200,"ml","<b>whole milk</b>, warm (35\u00b0C)"],["countN",100,"g","<b>butter</b>, melted (for d\u00e9trempe)"]]],["Lamination butter",[["countN",250,"g","<b>butter</b>, cold but pliable (82% fat preferred)"]]],["Finishing",[["countN",1,"","<b>egg</b>, beaten with 1 tbsp milk (egg wash)"]]]],"tl":[["T-00:00","Day 1: Make d\u00e9trempe","Mix dough, knead 8 min, refrigerate overnight",0],["T-24:00","Day 2: Laminate","3 single folds + 1 double fold (or 4 single folds), refrigerate between",0],["T-26:00","Day 3: Shape and prove","Roll, cut, shape crescents, prove 2-3 hours at 25\u00b0C",10800],["T-26:00","Bake","Egg wash, bake at 200\u00b0C for 15-20 min until deep golden",1200]],"steps":[["Make the d\u00e9trempe (Day 1)","Mix flour, sugar, yeast, and salt in a bowl. Add warm milk and melted butter. Mix until shaggy, then knead on a floured surface 8 min until smooth and elastic. Shape into a rectangle, wrap tightly, refrigerate overnight (12-16 hours).","Overnight resting develops flavour and relaxes gluten.",0],["Prepare butter (Day 2)","Pound cold butter between baking paper into a 15cm square, about 5mm thick. Keep it cold but pliable \u2014 it should bend without cracking. Refrigerate if too soft, let warm 5 min if too stiff.","Proper butter consistency is critical for clean lamination.",null],["First fold (single)","Roll d\u00e9trempe on a lightly floured surface into a 45x15cm rectangle. Place butter square on one half, leaving 2cm border. Fold other half over butter, sealing edges. Roll away from you to 45x15cm. Fold into thirds like a letter (single fold). Wrap, refrigerate 30 min.","First fold creates 3 butter layers; resting prevents gluten tearing.",1800],["Second fold (single)","Roll dough again to 45x15cm (short edge toward you). Fold into thirds (single fold). Wrap, refrigerate 30 min. Repeat this process 2 more times for a total of 4 single folds. (Alternatively: 3 single folds + 1 double fold for different layer structure).","Each fold triples layers: 4 single folds = 81 theoretical layers (reduces to ~27 actual).",1800],["Rest overnight","After final fold, wrap dough tightly and refrigerate overnight (8-12 hours). This rest is crucial \u2014 dough must be fully relaxed before rolling to prevent butter streaking.","Overnight rest ensures even butter distribution and clean lamination.",0],["Shape croissants (Day 3)","Roll dough on floured surface to 60x20cm rectangle, about 4mm thick. Trim edges. Cut diagonally into 8 isosceles triangles (base 12cm, height 20cm). Cut a 2cm slit in base of each triangle. Roll from base to point, curving ends into crescents. Place on baking trays, leaving 8cm space.","Proper shaping and spacing ensures even rising and full crescent form.",null],["Prove","Cover loosely with oiled cling film. Prove at 25\u00b0C for 2-3 hours until doubled in size and wobbly when tray is shaken. Dough should hold a fingerprint without springing back.","Slow, cool proving develops flavour and prevents butter melting.",10800],["Bake","Preheat oven to 200\u00b0C. Brush croissants with egg wash (avoid pooling). Bake at 200\u00b0C for 15-20 min until deep golden brown and cooked through (internal temperature 94\u00b0C). Cool on wire rack 10 min.","Egg wash creates colour; high heat ensures proper puff and crispiness.",1200],["Serve","Best served warm the same day. Reheat day-old croissants at 160\u00b0C for 5 min to refresh. Ideally served with butter and jam, or alongside caf\u00e9 au lait.","Fresh croissants are at their peak \u2014 store in airtight bag, refresh as needed.",null]]},{"slug":"lasagne-bolognese","t":"Lasagne","tier":"global","cui":"Italian \u00b7 Bologna","occ":["host","date"],"time":"2 hr 30 min","method":"Oven \u00b7 bake","diff":"Medium","blurb":"Bologna's pride \u2014 slow-cooked meat rag\u00f9, creamy b\u00e9chamel, fresh pasta layered and baked.","prov":{"popular_in":"Italian households and Sunday dinner tables globally","famous_for":"The classic lasagna with rag\u00f9 Bolognese and b\u00e9chamel (no ricotta!)","consists_of":"Fresh pasta sheets layered with slow-cooked beef-pork rag\u00f9 and creamy b\u00e9chamel, baked until bubbly","name_origin":"Lasagne alla Bolognese \u2014 from Bologna, Emilia-Romagna; traditional lasagne predates tomatoes","why_loved":"The combination of rich rag\u00f9, silky b\u00e9chamel, and tender pasta layers is Italian comfort at its finest","method_detail":"Oven \u2014 rag\u00f9 simmered 2+ hours, b\u00e9chamel made, pasta layered (rag\u00f9, b\u00e9chamel, parmigiano), baked 40-45 min, rested 15 min"},"brief":{"lead":"Build the classic lasagne alla Bolognese \u2014 a labour of love that rewards patience with deeply layered flavour. Start with a slow-cooked beef-pork rag\u00f9, craft a silky b\u00e9chamel, then layer with fresh pasta and generous Parmigiano.","expect":[["Slow cook","Rag\u00f9 simmers for 2+ hours to develop depth"],["Multi-stage","Make rag\u00f9, b\u00e9chamel, and assembly in sequence"],["Active layers","Assemble 4-5 layers carefully"],["Rest time","Essential for clean slices and set texture"]],"stats":[["150","min","Active"],["2","","Serves 2-4"],["190","\u00b0C","Oven"],["4-5","","Layers"]],"kit":["Large pot","Baking dish (20x25cm)","Saucepan","Whisk","Grater"]},"ing":[["Rag\u00f9",[["linear",250,"g","<b>beef</b> mince"],["linear",150,"g","<b>pork</b> mince"],["countN",1,"","onion, finely diced"],["countN",1,"","carrot, finely diced"],["countN",1,"","celery stalk, finely diced"],["countN",2,"","garlic cloves, minced"],["linear",100,"ml","red wine"],["linear",400,"g","tomato pur\u00e9e"],["linear",250,"ml","beef stock"],["linear",100,"ml","milk"],["taper",1,"tsp","<b>dried oregano</b>"],["static","","salt and black pepper"]]],["B\u00e9chamel",[["linear",50,"g","<b>butter</b>"],["linear",50,"g","plain flour"],["linear",600,"ml","<b>whole milk</b>, warmed"],["taper",1,"tsp","<b>salt</b>"],["taper",0.5,"tsp","<b>nutmeg</b>, grated"],["static","","white pepper"]]],["Assembly",[["linear",200,"g","fresh pasta sheets (or no-boil dried)"],["linear",100,"g","<b>Parmigiano-Reggiano</b>, grated"],["linear",30,"g","butter, cubed (for topping)"]]]],"tl":[["T-00:00","Start rag\u00f9","Saut\u00e9 vegetables, brown meats, simmer 2+ hours",0],["T-01:30","Make b\u00e9chamel","Roux technique, whisk in warm milk",0],["T-01:50","Assemble","Layer rag\u00f9, b\u00e9chamel, pasta, cheese",0],["T-02:10","Bake","40-45 min until golden and bubbly",1],["T-02:55","Rest","15 min before slicing",1]],"steps":[["Build the soffritto","Saut\u00e9 onion, carrot, celery in olive oil 8-10 min until soft. Add garlic, cook 1 min.","Foundational flavour base for authentic rag\u00f9.",null],["Brown the meats","Add beef and pork mince, brown well 8-10 min. Break up clumps, evaporate moisture.","Maillard reaction develops deep savoury depth.",null],["Deglaze and simmer","Add red wine, reduce 2 min. Stir in tomato pur\u00e9e, stock, milk, oregano. Simmer gently 90 min, stirring occasionally.","Wine adds acidity; long simmer melds flavours.",5400],["Make the b\u00e9chamel","Melt butter, stir in flour, cook 2 min. Whisk in warm milk gradually, simmer 5-8 min until thick. Season with salt, nutmeg, pepper.","Silky sauce layers bind the lasagne.",null],["Assemble first layers","Spread rag\u00f9 on dish bottom. Layer pasta, b\u00e9chamel, Parmigiano. Repeat 3 more times (rag\u00f9, pasta, b\u00e9chamel, cheese).","Even layers ensure consistent cooking.",null],["Finish and bake","Top with final pasta, remaining b\u00e9chamel, generous Parmigiano, butter cubes. Bake 40-45 min at 190\u00b0C until golden and bubbling.","Cheese and butter create golden crust.",2700],["Rest before serving","Cool 15 min uncovered. Cut squares with sharp knife.","Resting sets structure for clean slices.",900]]},{"slug":"quiche-lorraine","t":"Quiche Lorraine","tier":"global","cui":"French \u00b7 Lorraine","occ":["solo","date"],"time":"1 hr","method":"Oven \u00b7 bake","diff":"Medium","blurb":"France's brunch classic \u2014 buttery pastry with rich bacon-Gruy\u00e8re custard.","prov":{"popular_in":"French bistros and brunch tables globally","famous_for":"The classic French quiche with bacon and Gruy\u00e8re in rich egg-cream custard","consists_of":"Buttery pastry crust filled with bacon lardons, Gruy\u00e8re cheese, and eggs-cream custard, baked","name_origin":"From Lorraine region in northeast France; originally without cheese (purist version)","why_loved":"The silky-smooth custard, smoky bacon, and nutty Gruy\u00e8re in flaky pastry is brunch perfection","method_detail":"Oven \u2014 pastry shell blind-baked, bacon lardons crisped, custard (eggs, cream, milk, cheese) poured, baked 35-45 min until just set"},"brief":{"lead":"Master the French quiche Lorraine \u2014 buttery p\u00e2te bris\u00e9e shell filled with smoky bacon lardons, nutty Gruy\u00e8re, and silken egg-cream custard. Blind-bake the crust for flaky perfection, then bake until just set with a slight wobble.","expect":[["Chill pastry","Dough must rest 30 min minimum"],["Blind-bake","Essential for crisp crust"],["Crisp bacon","Render before adding to custard"],["Gentle bake","Low oven for silky custard"]],"stats":[["45","min","Active"],["2","","Serves 2-4"],["180","\u00b0C","Oven"],["35-45","min","Bake"]],"kit":["Tart tin (23cm)","Rolling pin","Baking beans","Whisk","Saucepan"]},"ing":[["Pastry",[["linear",150,"g","plain flour"],["linear",75,"g","<b>butter</b>, cold and cubed"],["taper",0.5,"tsp","<b>salt</b>"],["linear",30,"ml","ice-cold water"],["static","","egg wash (1 egg + 1 tbsp water)"]]],["Filling",[["linear",150,"g","<b>smoked bacon lardons</b>"],["linear",120,"g","<b>Gruy\u00e8re cheese</b>, grated"],["countN",3,"","large eggs"],["linear",200,"ml","<b>heavy cream</b>"],["linear",100,"ml","whole milk"],["taper",0.5,"tsp","<b>salt</b>"],["taper",0.5,"tsp","<b>white pepper</b>"],["taper",0.25,"tsp","<b>nutmeg</b>, grated"]]]],"tl":[["T-00:00","Make pastry","Rub butter into flour, rest 30 min chilled",0],["T-00:30","Roll and line","Press into tin, chill 15 min",0],["T-00:45","Blind-bake","Line with foil, beans, bake 20 min",1],["T-01:05","Crisp bacon","Render lardons until golden",0],["T-01:15","Mix custard","Whisk eggs, cream, milk, spices, cheese",0],["T-01:20","Assemble and bake","Layer bacon, pour custard, bake 35-45 min",1],["T-02:05","Cool and set","Rest 10 min before slicing",1]],"steps":[["Make p\u00e2te bris\u00e9e","Rub cold butter into flour and salt until crumb-like. Add ice water, bring together gently. Wrap, chill 30 min.","Cold butter creates flaky layers.",1800],["Line the tin","Roll dough 3mm thick, line tart tin, trim edges. Chill 15 min.","Chilling prevents shrinking during baking.",900],["Blind-bake crust","Prick base, line with foil and baking beans. Bake 20 min at 180\u00b0C. Remove foil, brush with egg wash, bake 5 min.","Ensures crisp, fully-cooked pastry base.",1500],["Crisp the bacon","Cook lardons in dry pan 6-8 min until golden and fat rendered. Drain on paper.","Rendering removes excess fat, concentrates flavour.",null],["Make custard","Whisk eggs, cream, milk, salt, pepper, nutmeg until smooth. Stir in 80g Gruy\u00e8re, bacon lardons.","Egg-cream ratio yields silky texture.",null],["Assemble and bake","Place remaining Gruy\u00e8re on crust base. Pour in custard. Bake 35-45 min at 160\u00b0C until just set with slight wobble.","Gentle bake prevents curdling and cracking.",2700],["Rest and serve","Cool 10 min before slicing. Serve warm or room temperature.","Resting allows custard to set completely.",600]]},{"slug":"spanakopita","t":"Spanakopita","tier":"exotic","cui":"Greek","occ":["solo","date"],"time":"1 hr","method":"Oven \u00b7 bake","diff":"Medium","blurb":"Greece's spinach pie \u2014 crisp phyllo layers with spinach, feta, and herbs.","prov":{"popular_in":"Greek households and meze tables globally","famous_for":"The classic Greek spinach and feta pie in crispy phyllo pastry","consists_of":"Spinach cooked with onions, herbs, mixed with feta cheese, wrapped in phyllo, baked until golden","name_origin":"Spanaki = 'spinach', pita = 'pie' \u2014 traditional Greek mezze dish","why_loved":"The crispy phyllo with salty-savoury spinach-feta filling is universally appealing","method_detail":"Oven \u2014 spinach wilted, drained, mixed with saut\u00e9ed onions, herbs, feta, layered in phyllo (buttered), baked 35-45 min until golden"},"brief":{"lead":"Craft authentic spanakopita \u2014 butter-brushed phyllo wrapped around spinach, feta, and aromatic herbs. Wilt and drain the spinach thoroughly, mix with saut\u00e9ed onions and fresh dill, then fold into crisp golden layers.","expect":[["Dry filling","Spinach must be well-drained to prevent soggy phyllo"],["Butter generously","Each phyllo layer needs brushing"],["Layer carefully","Fold bottom over top for rustic finish"],["Hot bake","High heat ensures golden crispness"]],"stats":[["50","min","Active"],["2","","Serves 2-4"],["180","\u00b0C","Oven"],["30-40","min","Bake"]],"kit":["Large frying pan","Baking tray (25x30cm)","Pastry brush","Colander","Mixing bowl"]},"ing":[["Filling",[["linear",500,"g","<b>spinach</b>"],["countN",2,"","onions, finely diced"],["countN",3,"","spring onions, chopped"],["countN",2,"","garlic cloves, minced"],["linear",200,"g","<b>feta cheese</b>, crumbled"],["countN",2,"","large eggs"],["linear",30,"g","fresh dill, chopped"],["linear",20,"g","fresh parsley, chopped"],["taper",0.5,"tsp","<b>salt</b>"],["taper",0.5,"tsp","<b>black pepper</b>"]]],["Phyllo",[["linear",250,"g","<b>phyllo pastry</b> sheets"],["linear",150,"g","<b>butter</b>, melted"],["linear",30,"ml","olive oil"]]]],"tl":[["T-00:00","Wilt spinach","Cook until wilted, drain thoroughly",0],["T-00:15","Saut\u00e9 aromatics","Cook onions and garlic in olive oil",0],["T-00:25","Mix filling","Combine spinach, onions, feta, herbs, eggs",0],["T-00:35","Layer phyllo","Butter sheets, fold in filling",0],["T-00:50","Bake","30-40 min until golden and crisp",1],["T-01:30","Rest briefly","5 min before cutting",1]],"steps":[["Wilt the spinach","Place spinach in large pan, wilt 3-4 min in batches. Cool in colander, squeeze out ALL liquid.","Removing moisture prevents soggy phyllo.",240],["Saut\u00e9 aromatics","Heat olive oil, cook onions 6-8 min until soft. Add garlic, spring onions, cook 2 min.","Building flavour foundation for filling.",480],["Mix the filling","Chop spinach finely. Combine with onions, feta, eggs, dill, parsley, salt, pepper. Mix well.","Eggs bind; feta provides salty punch.",null],["Prepare phyllo","Melt butter with little olive oil. Keep phyllo covered with damp cloth. Brush 5 sheets with butter, layer on tray.","Damp cloth prevents drying and cracking.",null],["Layer and fold","Spread filling in centre. Fold bottom phyllo over, then sides. Brush and layer 3 more sheets on top, tucking edges.","Rustic fold protects filling during bake.",null],["Score and bake","Brush top with butter. Score into diamonds with sharp knife (don't cut through). Bake 30-40 min at 180\u00b0C until golden.","Scoring helps portioning; butter aids browning.",2400],["Rest and serve","Cool 5 min. Cut along scored lines into squares or diamonds.","Brief rest sets structure for clean cuts.",300]]},{"slug":"eggs-benedict-hollandaise","t":"Eggs Benedict, Hollandaise","tier":"others","cui":"American \u00b7 French","occ":["date"],"time":"45 min","method":"Stovetop \u00b7 poach","diff":"Medium","blurb":"Brunch classic - poached eggs on ham-topped English muffins with hollandaise.","prov":{"popular_in":"American brunch spots; hotel restaurants worldwide","famous_for":"The definitive brunch dish - poached eggs, ham, and hollandaise","consists_of":"English muffins topped with ham, poached eggs, and hollandaise sauce","name_origin":"American invention; possibly named after Mr. Benedict or Benedictus","why_loved":"Perfect runny yolk, rich hollandaise, toasted muffin, brunch perfection","method_detail":"Stovetop - hollandaise made, muffins toasted, eggs poached, assembled"},"brief":{"lead":"Eggs Benedict is the ultimate brunch luxury - toasted English muffins crowned with ham, perfectly poached eggs, and silky hollandaise sauce. Mastering hollandaise emulsion and poaching timing delivers restaurant-quality results at home.","expect":[["Hollandaise first","Make and keep warm - sauce waits for eggs, not the reverse"],["Poach eggs","Create vortex, slip eggs in, cook exactly 3 min for runny yolks"],["Toast muffins","Butter and warm while eggs poach"],["Assemble fast","Muffin, ham, egg, sauce - serve immediately"]],"stats":[["30","min","Active"],["2","","Serves 2"],["Med","","Difficulty"],["4","","Muffin halves"]],"kit":["Saucepan","Slotted spoon","Whisk","Deep pan for poaching"]},"ing":[["Hollandaise",[["taper",3,"","<b>egg yolks</b>"],["taper",15,"ml","<b>lemon juice</b>"],["taper",250,"g","<b>butter</b>, melted and warm"],["taper",1,"tsp","<b>Dijon mustard</b>"],["taper",1,"tsp","<b>salt</b>"],["static","","cayenne pepper, to taste"],["static","","warm water, if needed"]]],["Poached eggs",[["countN",4,"","<b>eggs</b>"],["static","","white vinegar, for water"],["static","","salt, for water"]]],["Assembly",[["countN",2,"","<b>English muffins</b>, split"],["linear",200,"g","<b>ham</b> slices"],["taper",30,"g","<b>butter</b>, for muffins"],["static","","chives, finely chopped"],["static","","black pepper, to taste"]]]],"tl":[["T-00:00","Make hollandaise","Whisk yolks with lemon over heat, emulsify butter, season",0],["T-00:10","Warm serving plates","Heat plates in oven - eggs lose heat fast",0],["T-00:12","Toast muffins","Butter and keep warm",0],["T-00:15","Warm ham","Briefly pan-fry or grill slices",0],["T-00:20","Poach eggs","Vortex, slip in, 3 min exactly",0],["T-00:25","Assemble & serve","Muffin, ham, egg, hollandaise - immediately",0]],"steps":[["Make the hollandaise","Whisk egg yolks and lemon juice in a heatproof bowl over simmering water until thickened. Remove from heat, whisk in warm melted butter in thin stream until emulsified and thick. Stir in Dijon, salt, and cayenne. If too thick, whisk in warm water 1 tsp at a time. Keep warm (not hot) over warm water.","Emulsification creates silky sauce - heat separates it.",null],["Start poaching water","Fill deep pan with water, bring to simmer. Add splash of vinegar and pinch of salt - vinegar helps whites set.","Acid creates clean poached egg shape.",null],["Toast muffins","Split English muffins, toast cut side in buttered pan until golden and crisp. Keep warm on plates in low oven.","Crisp base prevents soggy assembly.",null],["Warm the ham","Pan-fry ham slices briefly in butter until warmed through and lightly browned at edges. Keep warm with muffins.","Warm ham melts into egg slightly.",null],["Poach the eggs","Create gentle vortex in simmering water with spoon. Crack each egg into small bowl, slip into vortex center. Poach exactly 3 minutes for runny yolks. Lift with slotted spoon, drain on paper towel.","3-minute poach yields perfect runny yolk.",180],["Assemble and serve","Place toasted muffin halves on plates. Top each with warm ham slice, then poached egg. Spoon hollandaise generously over eggs, covering yolks. Garnish with chives and cracked black pepper. Serve immediately - hollandaise waits for no one.","Fast assembly preserves heat and runny yolks.",null]]},{"slug":"flapjacks-pancakes","t":"Flapjacks (American Pancakes)","tier":"others","cui":"American \u00b7 Breakfast","occ":["solo","date"],"time":"30 min","method":"Stovetop \u00b7 griddle","diff":"Easy","blurb":"American breakfast classic - fluffy buttermilk pancakes with maple syrup.","prov":{"popular_in":"United States; breakfast diners; brunch menus worldwide","famous_for":"The American breakfast pancake - fluffy, stacked, syrup-drenched","consists_of":"Buttermilk pancakes cooked on griddle, served with butter and maple syrup","name_origin":"American flapjack; evolved from johnnycakes and hoe cakes","why_loved":"Fluffy interior, golden edges, stacked presentation, maple syrup sweetness","method_detail":"Stovetop - batter cooked on griddle until bubbly, flipped, served with butter and syrup"},"brief":{"lead":"American flapjacks are the comfort breakfast standard - thick, fluffy pancakes with golden edges and cloud-like interiors. Buttermilk creates tender crumb and tangy depth. Stack them high with butter and maple for pure weekend morning bliss.","expect":[["Mix batter","Combine wet and dry ingredients - lumps are fine"],["Rest batter","10 minutes while griddle heats - essential for fluffy rise"],["Cook pancakes","Bubbles form, edges set, flip once, golden both sides"],["Stack and serve","Butter each layer, drown in maple syrup"]],"stats":[["10","min","Active"],["2","","Serves 2-3"],["Easy","","Difficulty"],["8-10","","Pancakes"]],"kit":["Large bowl","Whisk","Griddle or heavy pan","Spatula"]},"ing":[["Dry ingredients",[["linear",250,"g","<b>plain flour</b>"],["taper",30,"g","<b>sugar</b>"],["taper",10,"g","<b>baking powder</b>"],["taper",1,"tsp","<b>baking soda</b>"],["taper",1,"tsp","<b>salt</b>"]]],["Wet ingredients",[["countN",2,"","<b>eggs</b>"],["linear",350,"ml","<b>buttermilk</b>"],["taper",60,"ml","<b>milk</b>"],["taper",60,"g","<b>butter</b>, melted"],["taper",1,"tsp","<b>vanilla extract</b>"]]],["Serving",[["static","","<b>butter</b>, for serving"],["static","","<b>pure maple syrup</b>, for serving"],["static","","fresh berries, optional"]]]],"tl":[["T-00:00","Mix dry ingredients","Whisk flour, sugar, baking powder, soda, salt in large bowl",0],["T-00:02","Mix wet ingredients","Whisk eggs, buttermilk, milk, melted butter, vanilla in separate bowl",0],["T-00:05","Combine batter","Pour wet into dry, whisk briefly - lumps are fine",0],["T-00:07","Heat griddle","Cast iron or nonstick pan, medium-low - test with water droplets",0],["T-00:10","Cook pancakes","Pour batter, wait for bubbles, flip once, repeat",0],["T-00:25","Stack and serve","Butter each pancake, stack 3-4 high, maple syrup over",0]],"steps":[["Combine dry ingredients","Whisk flour, sugar, baking powder, baking soda, and salt in large bowl until thoroughly combined.","Even distribution ensures uniform rise.",null],["Whisk wet ingredients","In separate bowl, whisk eggs, buttermilk, milk, melted butter, and vanilla until smooth.","Combined wet ingredients pour evenly into dry.",null],["Make batter","Pour wet ingredients into dry bowl. Whisk briefly just until combined - batter remains lumpy. DO NOT overmix - lumps will cook out. Let rest 10 minutes.","Overmixing creates tough pancakes. Resting activates leavening.",600],["Heat griddle","Heat heavy pan or griddle over medium-low heat. Test readiness - water droplets should sizzle and dance, not evaporate instantly. Brush lightly with butter.","Proper heat prevents burning before cooking through.",null],["Cook pancakes","Pour 60ml batter per pancake onto griddle. Cook until bubbles form on surface and edges look set (about 2 minutes). Flip once - cook second side until golden (1-2 minutes).","Single flip preserves fluffy interior.",null],["Keep warm","Transfer cooked pancakes to warm plate. Keep warm in low oven while cooking remaining batter. Brush griddle with butter between batches as needed.","Warm stack ensures even serving temperature.",null],["Serve","Stack 3-4 pancakes per plate. Place butter pats between layers. Pour maple syrup generously over top. Add fresh berries if desired. Serve immediately while hot.","Butter melts between layers for maximum richness.",null]]},{"slug":"churros-chocolate","t":"Churros & Chocolate","tier":"others","cui":"Spanish \u00b7 Street Food","occ":["solo","date"],"time":"30 min","method":"Frying \u00b7 piping","diff":"Medium","blurb":"Spanish street classic - crisp cinnamon-sugar churros with rich chocolate dipping sauce.","prov":{popular_in:'Spain and Latin America — the breakfast-of-the-night-before, the street snack of every fiesta',famous_for:'The piped fingers of choux-like dough, fried until crisp and ridged, rolled in cinnamon sugar, dunked into a cup of thick, dark, drinkable chocolate — the partnership is the dish',consists_of:'A hot water-and-flour dough (no egg, unlike choux), piped through a star nozzle into hot oil, fried golden, rolled in cinnamon sugar, served with a cup of dense, almost-pudding drinking chocolate',name_origin:'Churro — possibly from the churro sheep of Iberian shepherds whose horns the ridged pastry resembles; or from Portuguese \'chulé\'. The chocolate pairing is Spanish; in Mexico, champurrado stands in',why_loved:'Crunch, warmth, sugar and the bittersweet hit of chocolate that coats the tongue — the only dessert that doubles as a morning cure. Eaten with fingers, never forks',method_detail:'Stovetop — make the dough hot, pipe through a star tube straight into 180°C oil, fry until deep gold, drain briefly, toss in cinnamon sugar; serve at once with hot thick chocolate'},"brief":{"lead":"Churros are Spain's answer to doughnuts - star-shaped ridged dough piped directly into hot oil, fried until golden, and tossed in cinnamon sugar. The textural contrast of crisp exterior and tender interior pairs perfectly with thick dark chocolate for dipping.","expect":[["Make chocolate sauce","Melt chocolate with cream - make first, keep warm"],["Cook churro dough","Boil water and butter, stir in flour - thick ball forms"],["Pipe and fry","Pipe strips into hot oil, fry until golden, about 2 min per side"],["Sugar coat","Toss hot churros in cinnamon sugar, serve immediately with chocolate"]],"stats":[["25","min","Active"],["4","","Serves 4-6"],["Med","","Difficulty"],["12-15","","Churros"]],"kit":["Heavy saucepan","Piping bag with star tip","Deep fry or heavy pan","Slotted spoon"]},"ing":[["Chocolate sauce",[["linear",200,"g","<b>dark chocolate</b> (70%)"],["linear",200,"ml","<b>cream</b>"],["taper",30,"g","<b>butter</b>"],["taper",1,"tsp","<b>vanilla extract</b>"],["static","","pinch of salt"]]],["Churros dough",[["linear",250,"ml","<b>water</b>"],["taper",60,"g","<b>butter</b>"],["taper",2,"g","<b>salt</b>"],["taper",15,"g","<b>sugar</b>"],["linear",150,"g","<b>plain flour</b>"],["countN",2,"","<b>eggs</b>, lightly beaten"]]],["Frying and coating",[["static","","<b>oil</b> for deep frying (neutral oil)"],["linear",100,"g","<b>sugar</b>"],["taper",1,"tbsp","<b>ground cinnamon</b>"]]]],"tl":[["T-00:00","Make chocolate sauce","Melt chocolate with cream and butter, keep warm",0],["T-00:08","Heat frying oil","170C - thermometer essential for proper fry",0],["T-00:10","Make churro dough","Boil water, butter, salt, sugar - stir in flour off heat",0],["T-00:15","Pipe and fry","Pipe strips into hot oil, fry 2 min each side until golden",0],["T-00:25","Sugar coat","Toss hot churros in cinnamon sugar",0],["T-00:28","Serve","With warm chocolate sauce for dipping",0]],"steps":[["Make chocolate sauce","Heat cream in saucepan until just simmering. Remove from heat, add chopped dark chocolate. Let sit 2 minutes, then stir until melted and smooth. Add butter, vanilla, and pinch of salt. Keep warm over very low heat.","Rich chocolate complements crisp churros perfectly.",null],["Prepare coating","Mix sugar and cinnamon thoroughly in shallow bowl. Set aside near frying station.","Cinnamon sugar coating is essential churros tradition.",null],["Heat oil","Pour oil into deep fry or heavy pan to 5cm depth. Heat to 170C. Use thermometer - oil that's too cold makes greasy churros; too hot burns outside before cooking through.","Precise temperature ensures crisp, not greasy, results.",null],["Make churro dough","Bring water, butter, salt, and 15g sugar to boil in saucepan. Remove from heat, add flour all at once. Stir vigorously with wooden spoon until thick ball forms and pulls away from sides. Let cool 5 minutes. Beat in eggs one at a time until smooth, glossy paste forms.","Cooking flour gelatinizes starch for tender interior.",null],["Pipe churros","Transfer dough to piping bag fitted with large star tip. Pipe 10cm strips directly into hot oil, cutting with scissors. Don't overcrowd - fry 3-4 at a time.","Star tip creates signature ridged texture.",null],["Fry until golden","Fry churros about 2 minutes per side until deep golden all over. Lift with slotted spoon, drain briefly on paper towels.","Deep golden color indicates crisp exterior.",null],["Sugar coat and serve","Roll hot churros immediately in cinnamon sugar until coated. Pile on plate. Serve warm chocolate sauce in small bowls for dipping. Eat within hours - churros lose crispness as they cool.","Sugar adheres best to hot churros. Immediate serving preserves texture.",null]]},{"slug":"falafel-plate","t":"Falafel Plate","tier":"global","cui":"Middle Eastern","occ":["solo","date"],"time":"1 hr (plus soaking)","method":"Stovetop \u00b7 deep-fry","diff":"Medium","blurb":"The Middle Eastern staple - crispy chickpea fritters with tahini sauce, hummus, fresh herbs.","prov":{"popular_in":"Levantine countries and Middle Eastern restaurants globally","famous_for":"Crispy spiced chickpea fritters served with tahini and fresh vegetables","consists_of":"Dried chickpeas ground with herbs and spices, formed into balls, deep-fried until golden","name_origin":"From Arabic 'falafil' - peppers; possibly invented in Egypt as meat substitute during Lent","why_loved":"The crispy exterior, fluffy interior, and bright herb-spice flavour make them irresistible","method_detail":"Stovetop - dried chickpeas soaked 12-24 hours, ground with parsley, coriander, garlic, spices, formed, fried 3-4 min at 175\u00b0C"},"brief":{"lead":"Authentic falafel begins the night before with dried chickpeas - never canned. Soaked chickpeas are ground fresh with herbs and spices, shaped, and deep-fried until shatteringly crisp outside and fluffy inside. Serve with tahini sauce, warm pita, and a bright herb salad for the complete Middle Eastern plate experience.","expect":[["Soak","Dried chickpeas need 12-24 hours hydration - this is non-negotiable for texture"],["Prep","Ground chickpea mixture needs 30 minutes chilling to hold shape"],["Fry","Deep-fry at 175\u00b0C for 3-4 minutes until golden - double fry if needed for extra crisp"],["Serve","Immediate assembly with tahini, warm pita, pickles, and fresh vegetables"]],"stats":[["45","min","Active"],["2","","Serves 2-4"],["175","\u00b0C","Oil temp"],["12-24","hr","Soak"]],"kit":["Food processor","Deep pot or wok","Slotted spoon","Baking tray"]},"ing":[["Falafel",[["linear",250,"g","<b>dried chickpeas</b>"],["linear",80,"g","<b>fresh parsley</b>"],["linear",30,"g","<b>fresh coriander</b>"],["countN",4,"","<b>garlic cloves</b>"],["taper",1,"tbsp","<b>ground cumin</b>"],["taper",1,"tsp","<b>ground coriander</b>"],["taper",1,"tsp","<b>baking powder</b>"],["taper",1,"tsp","<b>salt</b>"],["static","","vegetable oil for frying"]]],["Tahini Sauce",[["linear",60,"ml","<b>tahini</b>"],["linear",60,"ml","<b>water</b>"],["taper",1,"tbsp","<b>lemon juice</b>"],["countN",1,"","<b>garlic clove</b>"],["taper",0.5,"tsp","<b>salt</b>"]]],["To Serve",[["linear",4,"","<b>pita breads</b>"],["static","","hummus"],["static","","pickled vegetables"],["linear",1,"","<b>tomato</b>, diced"],["linear",0.5,"","<b>cucumber</b>, sliced"],["static","","fresh mint and coriander leaves"]]]],"tl":[["T-00:00","Soak chickpeas","Cover dried chickpeas with plenty of cold water, soak 12-24 hours until plump",1],["T-00:00","Make tahini sauce","Whisk tahini, water, lemon juice, garlic, salt until smooth and creamy",0],["T-00:00","Prepare veg","Dice tomato, slice cucumber, pick herb leaves, warm pita",0],["T-00:00","Prep falafel mix","Drain soaked chickpeas well, pulse with herbs, garlic, spices until coarse crumb",0],["T-00:30","Chill mixture","Refrigerate 30 minutes - this helps shape hold together",1],["T-01:00","Heat oil","Heat vegetable oil to 175\u00b0C in deep pot",0],["T-01:00","Shape falafel","Form chickpea mixture into walnut-sized balls or patties",0],["T-01:00","Fry","Deep-fry 3-4 minutes until golden and crisp, drain on paper",0],["T-01:15","Assemble","Pile falafel on plates, drizzle tahini, serve with pita, hummus, fresh vegetables",0]],"steps":[["Soak the chickpeas","Place dried chickpeas in a large bowl and cover with plenty of cold water. Let soak 12-24 hours until plump and hydrated. Drain well before using.","Dried chickpeas need full hydration for proper texture - canned chickpeas make mushy falafel.",null],["Make the tahini sauce","Whisk tahini with water, lemon juice, minced garlic, and salt until smooth and creamy. Set aside - it will thicken slightly as it sits.","Tahini thickens when liquid is added, creating a creamy dipping sauce.",null],["Prepare the falafel mixture","Pulse drained chickpeas in a food processor with parsley, coriander, garlic, cumin, ground coriander, baking powder, and salt until finely chopped but not pureed - the texture should be coarse crumbs that hold together when squeezed.","Overprocessing creates paste - you want texture that binds, not hummus.",60],["Chill the mixture","Transfer falafel mixture to a bowl and refrigerate for 30 minutes. This step helps the mixture hold its shape when frying.","Chilling firms the mixture so balls don't fall apart in hot oil.",1800],["Heat the frying oil","Pour 5-7cm vegetable oil into a deep pot or wok and heat to 175\u00b0C. The oil is ready when a cube of bread browns in 15 seconds.","Proper temperature ensures crispy exterior without absorbing excess oil.",null],["Shape the falafel","Scoop tablespoons of chilled mixture and form into walnut-sized balls or small patties. Wet your hands slightly to prevent sticking.","Uniform size ensures even cooking - balls or patties both work.",null],["Fry until golden","Lower falafel into hot oil in batches and fry 3-4 minutes, turning occasionally, until deep golden brown and crisp. Drain on paper towels.","Frying time develops the signature crispy crust while cooking through.",240],["Serve immediately","Arrange falafel on plates, drizzle generously with tahini sauce, and serve with warm pita, hummus, pickled vegetables, diced tomato, cucumber, and fresh herbs.","Falafel is best enjoyed hot and crisp from the fryer.",null]]},{"slug":"gemista-stuffed-peppers-aubergine","t":"Gemista (Stuffed Peppers & Aubergine)","tier":"exotic","cui":"Greek \u00b7 Traditional","occ":["solo","date"],"time":"1 hr","method":"Oven \u00b7 bake","diff":"Medium","blurb":"Greek summer classic - vegetables stuffed with rice, herbs, and tomatoes, baked until tender.","prov":{"popular_in":"Greek households; summer vegetable dishes","famous_for":"The Greek summer vegetable casserole - stuffed, baked, served cold or warm","consists_of":"Hollowed vegetables stuffed with rice-herb filling, baked in tomato sauce","name_origin":"Greek gemista (filled); traditional summer preparation","why_loved":"Tender vegetables, flavourful rice filling, fresh herbs, versatile temperature","method_detail":"Oven - vegetables hollowed, stuffed with rice-herb mixture, baked in tomato sauce"},"brief":{"lead":"Gemista captures the essence of Greek summer cooking - sweet capsicums and tender aubergine roasted until melting, stuffed with a rice filling fragrant with dill, parsley, and tomatoes. The vegetables steam and roast simultaneously, creating layers of flavour. Excellent warm or at room temperature, making it perfect for entertaining or summer meals.","expect":[["Prep veg","Hollow vegetables carefully, keeping tops as lids - chop flesh for the filling"],["Make filling","Raw rice cooks inside the vegetables as they roast - do not par-cook"],["Stuff","Pack filling loosely - rice expands as it cooks"],["Roast","Bake covered then uncovered for tender, slightly char-topped vegetables"]],"stats":[["50","min","Active"],["1","hr","Oven"],["180","\u00b0C","Bake"],["2","","Serves 2-4"]],"kit":["Large baking dish","Sharp knife","Bowl","Foil"]},"ing":[["Vegetables",[["countN",4,"","<b>capsicums</b> (mixed colours)"],["countN",2,"","<b>aubergines</b>"],["countN",4,"","<b>large tomatoes</b>"]]],["Filling",[["linear",150,"g","<b>rice</b> (medium-grain)"],["countN",2,"","<b>onions</b>, finely chopped"],["countN",4,"","<b>spring onions</b>, chopped"],["linear",80,"g","<b>fresh parsley</b>, chopped"],["linear",40,"g","<b>fresh dill</b>, chopped"],["linear",60,"ml","<b>olive oil</b>"],["linear",400,"g","<b>tomato</b>, grated or chopped"],["taper",1,"tsp","<b>salt</b>"],["taper",0.5,"tsp","<b>black pepper</b>"]]],["Sauce",[["linear",200,"g","<b>passata</b> or tomato puree"],["linear",60,"ml","<b>olive oil</b>"],["taper",0.5,"tsp","<b>sugar</b>"]]],["To Serve",[["linear",100,"g","<b>feta cheese</b>, crumbled"],["static","","crusty bread"]]]],"tl":[["T-00:00","Preheat oven","Heat oven to 180\u00b0C",0],["T-00:00","Prep vegetables","Slice capsicum tops, hollow aubergines lengthwise, scoop tomato flesh",0],["T-00:00","Make filling","Mix raw rice, chopped onions, herbs, olive oil, grated tomato, salt, pepper",0],["T-00:15","Stuff vegetables","Fill vegetables loosely with rice mixture, replace capsicum lids",0],["T-00:20","Place in dish","Arrange stuffed vegetables in baking dish, tight packing helps steam",0],["T-00:20","Add sauce","Pour passata mixed with olive oil and sugar around vegetables",0],["T-00:20","Bake covered","Cover with foil, bake 45 minutes until vegetables tender",0],["T-01:05","Bake uncovered","Remove foil, bake 15 minutes for slightly golden tops",0],["T-01:20","Rest","Let rest 10 minutes before serving - helps flavours settle",1]],"steps":[["Prepare the vegetables","Slice the tops off capsicums and reserve as lids. Scoop out seeds and white membrane. Cut aubergines in half lengthwise and scoop out flesh, leaving 1cm shells. Grate or chop tomato flesh from 4 tomatoes, keeping the hollowed shells.","Hollowed vegetables become vessels for the rice filling as it steams and roasts.",900],["Make the rice filling","Combine raw rice, finely chopped onions, spring onions, parsley, dill, olive oil, grated tomato flesh, salt, and pepper in a large bowl. Mix well - the raw rice will cook inside the vegetables.","Raw rice expands as it roasts - this is the traditional Greek method.",null],["Stuff the vegetables","Fill capsicums and aubergine shells generously with rice mixture, packing loosely to allow for expansion. Place capsicum lids back on top. Fill hollowed tomato shells with filling.","Loose packing prevents bursting as rice expands during cooking.",null],["Arrange for baking","Place all stuffed vegetables in a large baking dish, packing them tightly. This helps create steam and keeps vegetables moist. In a small bowl, mix passata with olive oil and sugar, then pour around the vegetables.","Tight arrangement supports vegetables and creates self-basting steam.",null],["Bake covered","Cover baking dish tightly with foil. Bake at 180\u00b0C for 45 minutes until vegetables are tender when pierced with a knife and rice is cooked through.","Steaming under foil cooks rice and tenderises vegetables evenly.",2700],["Brown the tops","Remove foil and bake for another 15 minutes until the tops are slightly golden and the sauce has thickened around the vegetables.","Uncovered baking develops flavour and slight caramelisation.",900],["Rest before serving","Let the dish rest for 10 minutes out of the oven. This allows the filling to set slightly and flavours to settle.","Resting time makes serving easier and flavours more cohesive.",600],["Serve with feta","Transfer vegetables to plates, spoon over some of the tomato sauce from the dish, and crumble feta over the top. Serve with crusty bread to soak up the sauce.","Gemista is excellent warm, at room temperature, or cold - perfect for summer.",null]]},{"slug":"quesadillas","t":"Quesadillas","tier":"global","cui":"Mexican \u00b7 Street Food","occ":["solo"],"time":"20 min","method":"Stovetop \u00b7 griddle","diff":"Easy","blurb":"Mexican street classic - flour tortillas filled with cheese and folded until melty.","prov":{"popular_in":"Mexico; worldwide as quick meal or snack","famous_for":"The ultimate quick Mexican comfort - melty cheese in toasted tortilla","consists_of":"Flour tortillas filled with cheese, folded, cooked until golden and melted","name_origin":"Mexican quesadilla (little cheesy thing); from queso (cheese)","why_loved":"Crispy toasted tortilla, melty cheese, endless filling variations","method_detail":"Stovetop - tortillas filled with cheese, folded, cooked until golden and melted"},"brief":{"lead":"The perfect quick meal - quesadillas showcase the Mexican genius for transforming humble ingredients into something irresistible. Flour tortillas folded over melting cheese, griddled until crisp and golden. The classic version is just cheese, but add leftover chicken, saut\u00e9ed vegetables, or beans for a complete meal. Serve with salsa, guacamole, and coriander for the full street-food experience.","expect":[["Heat pan","Medium-high heat creates crisp tortilla without burning"],["Build","Layer cheese and fillings on one half, fold over"],["Griddle","Cook 2-3 minutes per side until golden and cheese melts"],["Serve","Cut into wedges, serve immediately with salsas and guacamole"]],"stats":[["20","min","Total"],["2","","Serves 1-2"],["Med-High","","Heat"],["4","","Quesadillas"]],"kit":["Large heavy pan","Spatula","Knife"]},"ing":[["Quesadillas",[["countN",4,"","<b>flour tortillas</b>"],["linear",150,"g","<b>Oaxaca cheese</b> or mozzarella, grated"],["taper",1,"tbsp","<b>butter</b> or oil"]]],["Optional Fillings",[["linear",100,"g","<b>cooked chicken</b>, shredded"],["linear",50,"g","<b>saut\u00e9ed peppers</b> and onions"],["linear",50,"g","<b>canned black beans</b>, drained"],["static","","any combination of above"]]],["To Serve",[["static","","salsa"],["static","","guacamole"],["linear",20,"g","<b>fresh coriander</b>"],["countN",1,"","<b>lime</b>, cut into wedges"]]]],"tl":[["T-00:00","Heat pan","Heat large pan over medium-high heat until hot",0],["T-00:00","Melt butter","Add butter or oil to pan, swirl to coat",0],["T-00:00","Build quesadilla","Place tortilla in pan, add cheese and fillings to one half, fold over",0],["T-00:02","Cook first side","Cook 2-3 minutes until golden underneath and cheese starts melting",0],["T-00:05","Flip and cook","Flip quesadilla, cook second side 2-3 minutes until golden and crisp",0],["T-00:08","Repeat","Repeat with remaining tortillas and cheese",0],["T-00:15","Cut and serve","Cut each quesadilla into wedges, serve immediately with salsas, guacamole, lime",0]],"steps":[["Heat the pan","Place a large heavy-based pan over medium-high heat and let it get hot - 2-3 minutes. The pan needs to be hot enough to crisp the tortilla quickly.","Hot pan creates crisp tortilla while cheese melts.",null],["Add fat to pan","Add butter or oil to the hot pan and swirl to coat the base. This prevents sticking and helps the tortilla crisp and colour.","Fat adds flavour and creates golden crispy tortilla.",null],["Build the quesadilla","Place one tortilla in the hot pan. Sprinkle grated cheese over one half of the tortilla. Add any optional fillings (chicken, peppers, beans) evenly over the cheese. Fold the empty half over the filling to create a half-moon shape.","Folding creates even cooking and easy handling.",null],["Cook first side","Cook the quesadilla for 2-3 minutes on the first side until the tortilla is golden brown and crisp underneath, and you can see the cheese beginning to melt.","First side crisps and starts the melting process.",180],["Flip and cook second side","Carefully flip the quesadilla with a spatula. Cook the second side for 2-3 minutes until golden brown and crisp, and the cheese is fully melted and gooey.","Second side completes the crisping and melts cheese fully.",180],["Repeat and serve","Repeat with remaining tortillas and cheese, adding more butter or oil to the pan as needed. Transfer cooked quesadillas to a board and cut each into 3-4 wedges.","Cutting into wedges makes them easy to dip and share.",null],["Serve with accompaniments","Arrange quesadilla wedges on plates and serve immediately with salsa, guacamole, fresh coriander, and lime wedges for squeezing over.","Quesadillas are best eaten hot and crisp from the pan.",null]]},{"slug":"beef-teriyaki","t":"Beef Teriyaki","tier":"global","cui":"Japanese \u00b7 Home Cooking","occ":["solo","date"],"time":"30 min (plus marinating)","method":"Grill \u00b7 grill","diff":"Easy","blurb":"Japanese home classic - beef grilled with sweet-savoury soy glaze.","prov":{"popular_in":"Japanese households; izakayas; worldwide teriyaki popularity","famous_for":"The Japanese sweet-savoury glaze that became a global favourite","consists_of":"Beef grilled with teriyaki sauce (soy, mirin, sugar, ginger)","name_origin":"Japanese teriyaki (teri=gloss, yaki=grill); cooking technique name","why_loved":"Sweet-savoury glaze, caramelised edges, tender beef, quick cooking","method_detail":"Grill - beef marinated, grilled, brushed with teriyaki glaze until caramelised"},"brief":{"lead":"A weeknight Japanese favourite - sirloin or ribeye steaks marinated in a soy-mirin glaze, seared in a smoking-hot pan until caramelised and glossy. Serve immediately over steamed rice with a side of miso soup and pickled vegetables.","expect":[["Quick","30-minute cook after 20-minute marinade"],["High heat","Sear in smoking-hot pan for caramelisation"],["Glossy finish","Teriyaki sauce reduces to sticky glaze"],["Tender","Slice against grain for maximum tenderness"]],"stats":[["30","min","Active"],["2","","Serves 2"],["Med","","Doneness"],["4","","Steaks"]],"kit":["Large frying pan or grill pan","Tongs","Sharp knife","Small saucepan"]},"ing":[["Marinade",[["linear",125,"ml","<b>soy sauce</b>"],["linear",60,"ml","<b>mirin</b>"],["linear",45,"ml","sugar"],["taper",1,"tbsp","grated <b>fresh ginger</b>"],["countN",2,"cloves","<b>garlic</b>, minced"],["taper",0.5,"tsp","freshly ground black pepper"]]],["Beef",[["linear",500,"g","<b>beef sirloin or ribeye</b> steaks (2-3cm thick)"]]],["Serving",[["static","","steamed rice"],["static","","miso soup"],["static","","pickled ginger or vegetables"],["static","","toasted sesame seeds"]]]],"tl":[["T-00:00","Make teriyaki sauce","Combine soy, mirin, sugar, ginger, garlic in pan, simmer 2 min",0],["T-00:05","Marinate beef","Cool sauce, coat beef, rest 20 min at room temperature",1],["T-00:25","Sear steaks","Sear 2-3 min per side in smoking-hot pan",0],["T-00:32","Glaze and rest","Brush with reduced sauce, rest 5 min",1],["T-00:37","Slice and serve","Slice against grain, serve over rice",0]],"steps":[["Make the teriyaki sauce","Combine soy sauce, mirin, sugar, ginger, garlic and black pepper in a small saucepan. Simmer for 2 minutes until sugar dissolves, then cool completely.","Cooking the sauce mellows the garlic and ginger while dissolving the sugar.",120],["Marinate the beef","Place beef in a shallow dish, pour cooled teriyaki sauce over, turning to coat. Let stand at room temperature for 20 minutes.","Room temperature meat sears evenly and stays tender.",1200],["Sear the steaks","Heat a large frying pan or grill pan over high heat until smoking. Remove beef from marinade (reserve sauce). Sear steaks 2-3 minutes per side for medium-rare.","High heat creates the caramelised crust essential to teriyaki.",150],["Glaze and rest","Return reserved marinade to pan, simmer 1 minute until syrupy. Brush over steaks. Remove to a board, rest loosely tented for 5 minutes.","Resting redistributes juices for tender meat; glaze adds glossy finish.",300],["Slice and serve","Slice beef against the grain into thin strips. Serve immediately over steamed rice with remaining sauce drizzled over, plus miso soup and pickles.","Slicing against grain maximises tenderness; rice balances the salty-sweet glaze.",null]]},{"slug":"braai-lamb-chops-chimichurri","t":"Braai Lamb Chops, Chimichurri","tier":"premium","cui":"South African \u00b7 Argentine","occ":["host","date"],"time":"40 min (plus marinating)","method":"Braai \u00b7 grill","diff":"Medium",  pair: [["Wine","Stellenbosch Syrah","South Africa","The Syrah's black pepper and dark berry mirror the lamb's char, while a whisper of spice laces the chimichurri's bright, green herbs."],["Beer","SA craft IPA","South Africa","A brisk, piney IPA scrubs the lamb's richness clean and lifts every last clove of garlic off the bone."],["Non-alcoholic","Ginger beer","South Africa","Fiery ginger beer cuts through the fat and sings in the same bright, zesty key as the chimichurri."]],
  "blurb":"Lamb chops grilled over coals, served with vibrant Argentine chimichurri sauce.","prov":{popular_in:'A staple of South African weekends, where chops meet open flame at every braai from the Cape coast to the platteland, eaten standing with a drink close at hand.',famous_for:'Lamb cutlets charred at the edges and blushing within, their richness cut by a bright, herb-flecked chimichurri that sparks vivid green against the dark, smouldering meat.',consists_of:'Lamb chops grilled over hot coals and finished with a chimichurri of parsley, oregano, garlic, chilli, red wine vinegar, and good oil, spooned over while the meat is still warm.',name_origin:'‘Braai’ is Afrikaans for ‘roast’ or ‘grill’, the open hearth of South African gathering; chimichurri is Argentine, its exact origins debated but its parsley-garlic soul unmistakable.',why_loved:'Smoke, fire, and fresh herb sharpness in one bite — the flavour of a long afternoon that refuses to end, shared from a single smoking grid.',method_detail:'Braai — grill hot over coals, rest, then dress with sauce'},"brief":{"lead":"A fusion favourite - well-trimmed lamb chops marinated in olive oil and garlic, grilled over hot coals until charred and smoky, served with a bright, herbaceous chimichurri sauce. The sauce cuts through the rich lamb with vinegar and fresh herbs, while open-fire cooking adds that signature South African braai flavour. Serve with pap, grilled vegetables or a fresh salad.","expect":[["Open fire","Grilled over hot coals for smoky char"],["Marinated","20 minutes in oil and garlic"],["Vibrant sauce","Fresh parsley, garlic and vinegar"],["Medium doneness","3-4 minutes per side for pink, tender lamb"]],"stats":[["35","min","Active"],["4","","Serves 4"],["Med","","Doneness"],["8","","Chops"]],"kit":["Braai grid or braai tongs","Small mixing bowl","Chopping board","Brush for oiling"]},"ing":[["Lamb",[["linear",8,"","<b>lamb chops</b> (well-trimmed, 2-3cm thick)"],["linear",45,"ml","<b>olive oil</b>"],["countN",4,"cloves","<b>garlic</b>, minced"],["taper",1,"tsp","salt"],["taper",0.5,"tsp","freshly ground black pepper"]]],["Chimichurri",[["linear",60,"g","packed fresh <b>parsley</b> leaves"],["countN",4,"cloves","<b>garlic</b>, roughly chopped"],["linear",60,"ml","<b>olive oil</b>"],["linear",45,"ml","<b>red wine vinegar</b>"],["taper",0.5,"tsp","<b>dried oregano</b>"],["taper",0.25,"tsp","salt"],["taper",0.25,"tsp","freshly ground black pepper"],["static","","chilli flakes to taste"]]],["Serving",[["static","","pap or potato wedges"],["static","","grilled vegetables or salad"]]]],"tl":[["T-00:00","Make chimichurri","Blend herbs, garlic, oil, vinegar, spices, rest 10 min",0],["T-00:10","Marinate lamb","Coat chops in oil-garlic mix, rest 20 min",1],["T-00:30","Prepare fire","Heat coals until medium-hot (you can hold hand 5cm above for 3 sec)",1],["T-00:35","Grill chops","Sear 3-4 min per side over medium-hot coals",0],["T-00:44","Rest and serve","Rest 5 min, serve with chimichurri",1]],"steps":[["Make the chimichurri sauce","Place parsley, garlic, olive oil, red wine vinegar, oregano, salt, pepper and chilli flakes in a blender. Pulse until roughly chopped but still textured. Pour into a bowl and rest for 10 minutes to meld flavours.","Resting allows herbs and garlic to infuse the oil and vinegar.",600],["Marinate the lamb","Mix olive oil, minced garlic, salt and pepper in a shallow dish. Coat lamb chops thoroughly, turning to cover both sides. Let stand at room temperature for 20 minutes.","Marinating adds flavour and helps the lamb sear, not steam.",1200],["Prepare the braai","Build a medium-hot fire - you should be able to hold your hand 5cm above the coals for 3 seconds. Rake the coals into an even bed.","Medium heat allows fat rendering without burning the exterior.",60],["Grill the chops","Place lamb on the braai grid over medium-hot coals. Grill for 3-4 minutes per side for medium-rare to medium, turning once. The chops should develop a rich, charred crust.","Open-fire cooking creates the signature smoky flavour of a braai.",240],["Rest and serve","Remove chops to a board, loosely tent with foil, and rest for 5 minutes. Serve with chimichurri spooned generously over, alongside pap, potato wedges or grilled vegetables.","Resting redistributes juices for tender meat; chimichurri's acidity cuts the richness.",300]]},{"slug":"pap","t":"Pap (Mealie Meal)","tier":"signature","cui":"South African","occ":["solo","host"],"time":"30 min","method":"Stovetop \u00b7 simmer","diff":"Easy","blurb":"South Africa's daily bread - maize meal porridge, from crumbly phutu to smooth slap pap, the base of every meal.","prov":{"popular_in":"Every South African home, across all cultures","famous_for":"Being the universal staple that accompanies stews, braais and curries nationwide","consists_of":"Maize meal cooked with water and salt into a stiff porridge, ranging from crumbly (phutu) to smooth (slap pap)","name_origin":"'Pap' is Afrikaans for porridge; maize meal was introduced by Dutch traders and became the staple crop","why_loved":"Humble, filling and endlessly versatile - the foundation of South African cuisine","method_detail":"Stovetop - water brought to boil, maize meal added while stirring, simmered 20-30 min until desired texture, stiff for phutu, softer for slap pap"},"brief":{"lead":"The foundation of South African cooking - fine maize meal cooked with salted water into a smooth, thick porridge. For phutu (crumbly pap), cook to a stiff texture that breaks apart in soft mounds. For slap pap (smooth porridge), add more water and cook longer until silky. Serve immediately as the perfect accompaniment to curries, stews and braais, or with milk and sugar for breakfast.","expect":[["One pot","Cooked entirely in a single heavy pot"],["Constant stirring","Prevents lumps and ensures smoothness"],["Texture choice","Stiff phutu or smooth slap pap"],["Immediate serving","Best served hot, straight from the stove"]],"stats":[["25","min","Active"],["4","","Serves 4"],["Easy","","Difficulty"],["250","g","Mealie meal"]],"kit":["Heavy-based pot (3 litres)","Long-handled wooden spoon","Measuring jug","Ladle"]},"ing":[["Pap",[["linear",1,"l","<b>water</b>"],["linear",250,"g","<b>maize meal</b> (fine white mealie meal)"],["taper",0.5,"tsp","<b>salt</b>"]]],["Serving variations",[["static","","milk and sugar (for breakfast pap)"],["static","","tomato and onion (for tomato pap)"],["static","","stews, curries or braai meats"]]]],"tl":[["T-00:00","Boil water","Bring salted water to rolling boil in heavy pot",0],["T-00:05","Add maize meal","Pour in steady stream while stirring constantly",0],["T-00:10","First simmer","Cook 5 min over low heat, stirring occasionally",0],["T-00:15","Second cook","Cover and cook 10-15 min for phutu (20 min for slap pap)",0],["T-00:30","Beat and serve","Beat with wooden spoon until smooth, serve hot",0]],"steps":[["Bring water to boil","Place water and salt in a heavy-based pot and bring to a rolling boil over high heat. A heavy pot prevents scorching.","Boiling water prevents lumps when maize meal is added.",120],["Add the maize meal","Pour maize meal into the boiling water in a steady stream with one hand while stirring vigorously with the other hand using a wooden spoon.","Stirring while adding prevents lumps from forming.",180],["First simmer","Reduce heat to low, cover, and simmer for 5 minutes, stirring once or twice to prevent sticking.","Initial cooking softens the maize meal grains.",300],["Second cook for texture","For phutu (stiff, crumbly pap), cook another 10-15 minutes until very thick and pulls away from the sides. For slap pap (smooth, soft porridge), add 125ml more water and cook another 15-20 minutes until silky.","Longer cooking breaks down grains for desired texture.",900],["Beat and serve","Remove from heat and beat vigorously with the wooden spoon until smooth and glossy. Serve immediately in soft mounds alongside stews, curries or braai meats, or with milk and sugar for breakfast.","Beating aerates the pap for lighter texture; serves best hot.",60]]},{"slug":"naan-bread","t":"Naan Bread","tier":"others","cui":"Indian \u00b7 Traditional","occ":["solo","date"],"time":"1 hr (plus proving)","method":"Oven \u00b7 bake","diff":"Medium","blurb":"Indian flatbread classic - soft, pillowy naan baked in a hot tandoor or oven.","prov":{"popular_in":"Throughout India; Indian restaurants worldwide","famous_for":"The essential Indian bread - soft, slightly charred, perfect for curries","consists_of":"Yogurt-leavened dough baked at high heat until puffed and lightly charred","name_origin":"Persian n\u0101n (bread); Mughal-era introduction to India","why_loved":"Soft pillowy texture, slight char flavour, perfect for scooping curries","method_detail":"Oven - dough proved, divided, baked at 260C until puffed and charred"},"brief":{"lead":"A classic Indian flatbread made with yogurt-leavened dough, baked at high heat to achieve the signature puffy, lightly charred exterior and soft, pillowy interior. Perfect for scooping up curries and gravies.","expect":[["1 hour","Active cooking and proving time"],["8","Pieces","Soft, pillowy flatbreads"],["260\u00b0C","Oven temperature","Very hot baking"],["15 min","Bake time","Until puffed and charred"]],"stats":[["60","min","Total time"],["8","","Pieces"],["260\u00b0C","Oven","Very hot"],["Med","","Doneness"]],"kit":["Large bowl","Baking sheet","Rolling pin","Oven"]},"ing":[["Dough",[["linear",500,"g","<b>plain flour</b>"],["taper",7,"g","<b>dried yeast</b>"],["linear",1,"tsp","<b>sugar</b>"],["linear",250,"ml","<b>milk</b>, warmed"],["linear",150,"g","<b>yoghurt</b>"],["taper",1,"tsp","<b>salt</b>"]]],["Topping",[["linear",50,"g","<b>butter</b>, melted"],["countN",2,"cloves","<b>garlic</b>, minced"]]]],"tl":[["T-00:00","Activate yeast","Mix yeast, sugar and warm milk, let stand 10 min until foamy",0],["T-00:10","Mix dough","Combine flour, salt, yeast mixture and yoghurt, knead 8 min until smooth and elastic",0],["T-00:18","First prove","Cover bowl, leave in warm place 1 hour until doubled",1],["T-01:18","Divide dough","Punch down, divide into 8 equal pieces, roll into balls",0],["T-01:25","Shape naan","Roll each ball into oval teardrop shape, 5mm thick",0],["T-01:35","Preheat oven","Heat oven to 260\u00b0C with baking sheet inside",0],["T-01:40","Bake naan","Cook 2-3 pieces at a time on hot sheet, 4-5 min until puffed and charred spots appear",0],["T-01:55","Brush with butter","Brush hot naan with garlic butter, serve immediately",0]],"steps":[["Activate the yeast","Mix the yeast, sugar and warm milk in a large bowl. Let stand for 10 minutes until foamy and active.","Yeast needs warmth and sugar to activate and bubble.",600],["Mix the dough","Add the flour, salt and yoghurt to the yeast mixture. Mix to combine, then knead for 8 minutes until smooth and elastic.","Kneading develops gluten for stretch and soft texture.",480],["First prove","Cover the bowl with a damp cloth and leave in a warm place for 1 hour until doubled in size.","Proving allows yeast to ferment and dough to rise.",3600],["Divide and shape","Punch down the dough and divide into 8 equal pieces. Roll each piece into a ball, then roll into oval teardrop shapes about 5mm thick.","Individual portions ensure even cooking and puffing.",null],["Preheat oven","Heat oven to 260\u00b0C with a baking sheet inside. The sheet must be very hot.","Maximum heat mimics tandoor temperature for proper puff.",null],["Bake the naan","Place 2-3 naan on the hot baking sheet. Bake for 4-5 minutes until puffed up with golden charred spots.","Hot surface creates steam pockets for pillowy texture.",300],["Brush with butter","Mix melted butter with minced garlic. Brush hot naan generously with garlic butter and serve immediately.","Garlic butter adds authentic flavour and gloss.",null]]},{"slug":"mealie-bread","t":"Mealie Bread","tier":"premium","cui":"South African \u00b7 Afrikaans","occ":["host","date"],"time":"1 hr","method":"Oven \u00b7 bake","diff":"Easy",  pair: [["Wine","Unwooded Chenin Blanc","South Africa","Crisp, unoaked Chenin mirrors the corn's sweetness with a zesty snap that keeps each buttery bite bright."],["Beer","Castle Lager","South Africa","An ice-cold Castle lets the sweet, golden cornbread shine, washing it down with clean, biscuity refreshment."],["Non-alcoholic","Ginger beer","South Africa","Fizzy ginger beer's gentle warmth is a cheerful partner to the bread's mellow, sweet corn."]],
  "blurb":"Sweet corn bread \u2014 moist, golden and flecked with corn kernels, a beloved braai side and tea-time treat.","prov":{"popular_in":"South African bakeries and home kitchens","famous_for":"The moist, pudding-like texture and sweet corn flavour that makes it irresistible","consists_of":"Fresh corn kernels folded into a quick-bread batter of flour, sugar, eggs and milk, baked until golden","name_origin":"'Mealie' is Afrikaans for maize/corn; a traditional quick bread using fresh sweetcorn","why_loved":"Sweet, moist and golden \u2014 the perfect accompaniment to braais or enjoyed with tea","method_detail":"Oven \u2014 corn kernels mixed into a batter of flour, baking powder, sugar, eggs and milk, poured into a tin, baked at 180\u00b0C 35\u201345 min until golden and cooked"},"brief":{"lead":"A beloved South African quick bread, moist and golden with fresh corn kernels throughout. Sweet, pudding-like texture makes it perfect alongside braais or enjoyed with butter and tea.","expect":[["1 hour","Total time including baking"],["1","Loaf","9x23cm standard loaf tin"],["180\u00b0C","Oven temperature","Moderate baking"],["35-45 min","Bake time","Until golden and set"]],"stats":[["60","min","Total time"],["1","","Loaf"],["180\u00b0C","Oven","Moderate"],["Med","","Doneness"]],"kit":["Loaf tin","Mixing bowls","Grater","Oven"]},"ing":[["Corn preparation",[["countN",2,"","<b>fresh corn cobs</b> (about 250 g kernels)"]]],["Batter",[["linear",360,"g","<b>cake flour</b>"],["taper",15,"ml","<b>baking powder</b>"],["linear",150,"g","<b>sugar</b>"],["taper",1,"tsp","<b>salt</b>"],["countN",2,"","<b>eggs</b>"],["linear",250,"ml","<b>milk</b>"],["linear",100,"g","<b>butter</b>, melted"]]]],"tl":[["T-00:00","Preheat oven","Heat oven to 180\u00b0C and grease a 23x9cm loaf tin",0],["T-00:05","Prepare corn","Cut kernels from cobs, about 250 g",0],["T-00:10","Mix dry ingredients","Sift flour, baking powder and salt into large bowl",0],["T-00:15","Combine wet ingredients","Whisk eggs and sugar until pale, add milk and melted butter",0],["T-00:22","Fold together","Fold wet into dry, then fold in corn kernels until just combined",0],["T-00:27","Bake","Pour into tin, bake 35-45 min until golden and skewer comes out clean",0],["T-01:15","Cool briefly","Cool in tin 10 min, then turn out",0]],"steps":[["Preheat oven","Heat oven to 180\u00b0C and generously grease a 23x9cm loaf tin with butter.","Proper preparation prevents sticking and ensures even baking.",null],["Prepare corn","Cut the kernels from the corn cobs. You should have about 250 g of fresh corn kernels.","Fresh corn provides moisture and natural sweetness.",null],["Mix dry ingredients","Sift the cake flour, baking powder and salt into a large mixing bowl.","Sifting aerates flour and distributes leavening evenly.",null],["Combine wet ingredients","Whisk the eggs and sugar until pale and thick. Add the milk and melted butter, whisking to combine.","Whisking adds air for lighter texture.",null],["Fold together","Fold the wet mixture into the dry ingredients until just combined. Gently fold in the corn kernels.","Minimal mixing keeps bread tender; corn stays intact.",null],["Bake the bread","Pour the batter into the prepared tin. Bake for 35-45 minutes until golden and a skewer comes out clean.","Even baking sets the structure and cooks through.",2700],["Cool and serve","Cool in the tin for 10 minutes, then turn out onto a wire rack. Serve warm with butter.","Brief cooling sets the crumb for slicing.",600]]},{"slug":"roosterkoek","t":"Roosterkoek","tier":"signature","cui":"South African \u00b7 Afrikaans","occ":["host","date"],"time":"45 min (plus proving)","method":"Fire \u00b7 braai","diff":"Easy",  pair: [["Wine","Pinotage rosé","South Africa","A chilled rosé brings red-berry freshness that flirts with the bread's smoky, charred edges."],["Beer","Windhoek Lager","South Africa","Nothing beats an ice-cold lager torn into a hot, smoky roosterkoek straight off the coals — pure braai bliss."],["Non-alcoholic","Ginger beer","South Africa","Spicy ginger beer is the braai's refreshing sidekick, cutting through the rich, buttery bread."]],
  "blurb":"Braai bread at its best \u2014 yeasted dough balls cooked over hot coals, crisp outside and pillowy soft within.","prov":{popular_in:'Hand-shaped over the coals at every South African braai, served straight from the grid to grateful, sauce-ready hands that have been waiting since the fire was lit.',famous_for:'Round bread rolls with a crackling, char-spotted crust and a soft, smoky crumb that tears open to release a warm puff of steam and the scent of the fire.',consists_of:'A simple yeasted bread dough, lightly risen and shaped into rounds, then baked directly over hot coals on a grid until hollow-sounding when tapped underneath.',name_origin:'Afrikaans for ‘grill bread’ — rooster (‘grill’ or ‘grid’) and koek (‘cake’ or ‘bread’) name both the method and the humble, beloved loaf it produces.',why_loved:'Eaten hot with melting butter or a slick of jam, it is the braai’s quiet centrepiece — the thing everyone reaches for first, before the meat is even ready.',method_detail:'Braai — grill dough rounds directly over the coals'},"brief":{"lead":"The ultimate braai bread \u2014 simple yeasted dough balls cooked directly over hot coals for a smoky, charred exterior and pillowy soft interior. Torn fresh from the fire with melting butter, it's braai perfection.","expect":[["1 hour proving","Rise time for dough"],["8","Pieces","Dough balls for braai"],["Moderate coals","Fire temperature","Even heat, no flames"],["8-12 min per side","Grill time","Until golden and hollow"]],"stats":[["60","min","Proving time"],["8","","Pieces"],["Med","Coals","Moderate heat"],["12","min per side","Grill time"]],"kit":["Braai grid","Mixing bowl","Fire tongs","Brush"]},"ing":[["Dough",[["linear",500,"g","<b>bread flour</b>"],["taper",7,"g","<b>dried yeast</b>"],["linear",1,"tbsp","<b>sugar</b>"],["taper",1,"tbsp","<b>salt</b>"],["linear",250,"ml","<b>warm water</b>"],["linear",100,"ml","<b>milk</b>, warmed"],["linear",50,"g","<b>butter</b>, melted"]]],["Serving",[["linear",50,"g","<b>butter</b>, for brushing"],["static","","<b>garlic</b> or herbs (optional)"]]]],"tl":[["T-00:00","Activate yeast","Mix yeast, sugar and warm water, let stand 10 min until foamy",0],["T-00:10","Mix dough","Combine flour, salt, yeast mixture, milk and butter, knead 8 min until smooth",0],["T-00:18","First prove","Cover bowl, leave in warm place 1 hour until doubled",1],["T-01:18","Prepare coals","Build moderate bed of coals, let flames die down",0],["T-01:25","Shape balls","Divide dough into 8 pieces, roll into tight balls",0],["T-01:32","Grill roosterkoek","Place on grid over moderate coals, grill 8-12 min per side until golden and hollow-sounding",0],["T-01:55","Brush and serve","Brush with melted butter immediately, serve warm",0]],"steps":[["Activate the yeast","Mix the yeast, sugar and warm water in a large bowl. Let stand for 10 minutes until foamy.","Yeast needs warmth and sugar to activate and bubble.",600],["Mix the dough","Add the flour, salt, warm milk and melted butter to the yeast mixture. Mix and knead for 8 minutes until smooth and elastic.","Kneading develops gluten for structure and chew.",480],["First prove","Cover the bowl with a damp cloth and leave in a warm place for 1 hour until doubled in size.","Proving allows yeast to ferment and dough to rise.",3600],["Prepare the coals","Build a moderate bed of coals and let the flames die down. The coals should be glowing with no active flames.","Moderate, even heat prevents burning and ensures proper cooking.",null],["Shape the balls","Punch down the dough and divide into 8 equal pieces. Roll each piece into a tight ball.","Tight balls create interior structure for even grilling.",null],["Grill the roosterkoek","Place the dough balls on a braai grid over moderate coals. Grill for 8-12 minutes per side until golden brown and hollow-sounding when tapped.","Direct fire contact creates smoky char and pillowy puff.",720],["Brush and serve","Brush the hot roosterkoek generously with melted butter (add garlic or herbs if desired). Serve immediately alongside the braai.","Butter adds richness and gloss; garlic creates authentic flavour.",null]]}]);